รับทราบครับ ผมจะเพิ่ม Dropdown สำหรับเลือก Model (Gemini 2.5 Flash หรือ Gemini 3 Pro) ลงในส่วน Control Panel ระหว่าง Image Style และ Aspect Ratio เพื่อให้ท่านสามารถเลือกใช้โมเดลที่ต้องการในการสร้างภาพได้ครับ

นี่คือโค้ดที่อัปเดตครับ:

# Updated files:

## services/geminiService.ts

Update `generateStoryImage` to accept a `model` parameter, allowing dynamic model selection.

```typescript
import { GoogleGenAI, Modality } from "@google/genai";
import { Character } from '../types';
import { fileToBase64 } from "../utils/fileUtils";

if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateStoryImage = async (
    prompt: string, 
    characters: Character[], 
    aspectRatio: string, 
    imageStyle: string,
    model: string = 'gemini-2.5-flash-image'
): Promise<string> => {

    const characterNames = characters.map(c => c.name).join(' and ');

    let styleDirective = '';
    if (imageStyle === 'Match Reference') {
      styleDirective = 'The overall artistic style (e.g., cartoon, anime, realistic) must perfectly match the reference images.';
    } else if (imageStyle === 'Black & White (Laser Printer)') {
      styleDirective = 'The artistic style must be a high-contrast, clean black and white line art, specifically optimized for printing on a monochrome laser printer. Use solid blacks and whites and avoid shades of gray to ensure maximum clarity and print quality. The character\'s core features must still strictly match the reference images.';
    } else {
      styleDirective = `The overall artistic style must be **${imageStyle}**, while ensuring the character's core features (face, hair, etc.) strictly match the reference images to maintain consistency.`;
    }

    const fullPrompt = `
**Objective:** Create a visually consistent, high-resolution 4K image for a story sequence using the provided reference images/frames.

**Scene Description:**
${prompt}

**Characters Involved:**
${characterNames}

**Core Directives (Strictly follow):**

1.  **UNWAVERING CHARACTER CONSISTENCY (HIGHEST PRIORITY):**
    *   **Multiple References Provided:** You are given multiple reference images for each character to capture their appearance from various angles.
    *   **Face & Features:** The character's face, eyes, nose, mouth, and all facial features MUST be an exact, consistent match derived from the provided reference frames. Synthesize a coherent 3D understanding of the face from all frames.
    *   **Hairstyle & Color:** Replicate the exact hairstyle and color from the references.
    *   **Clothing & Attire:** The character's outfit MUST remain consistent with the reference images unless the prompt explicitly asks for a change.
    *   **Art Style:** ${styleDirective}

2.  **SCENE & BACKGROUND CONTINUITY:**
    *   Render the scene based on the description above.
    *   Maintain a consistent artistic style for the background and environment to ensure it feels like the same world across different images.

3.  **Technical Specifications:**
    *   **Aspect Ratio:** Strictly adhere to a ${aspectRatio} aspect ratio.

**Final Check:** Before finalizing, verify that the characters in the generated image are indistinguishable from their composite reference images.
`.trim();

    const parts: any[] = [{ text: fullPrompt }];

    for (const character of characters) {
        if (character.referenceFrames.length > 0) {
            for (const frame of character.referenceFrames) {
                parts.push({
                    inlineData: {
                        data: frame.data,
                        mimeType: frame.mimeType,
                    },
                });
            }
        }
    }

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: {
                responseModalities: [Modality.IMAGE],
                imageConfig: {
                    aspectRatio: aspectRatio,
                },
            },
        });

        const candidate = response.candidates?.[0];
        const firstPart = candidate?.content?.parts?.[0];

        if (firstPart && firstPart.inlineData) {
            const base64ImageBytes = firstPart.inlineData.data;
            return `data:${firstPart.inlineData.mimeType};base64,${base64ImageBytes}`;
        } else {
             // Check for safety ratings or other reasons for no content
            if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
                 throw new Error(`Image generation stopped unexpectedly. Reason: ${candidate.finishReason}. Please check your prompt for safety violations.`);
            }
            throw new Error("No image data received from API. The prompt might be too complex or the response was empty.");
        }

    } catch (error) {
        console.error("Gemini API call failed:", error);
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("An unexpected error occurred while calling the Gemini API.");
    }
};

export const expandImage = async (imageDataUrl: string, newAspectRatio: string, originalPrompt: string): Promise<string> => {
    const model = 'gemini-2.5-flash-image';

    const [header, base64Data] = imageDataUrl.split(',');
    if (!header || !base64Data) {
        throw new Error("Invalid imageDataUrl format");
    }
    const mimeType = header.match(/:(.*?);/)?.[1] || 'image/png';

    const fullPrompt = `
**Objective:** You are an expert image editor AI. Your task is to expand the given image to a new aspect ratio of **${newAspectRatio}**.

**Core Directives (Strictly follow):**
1.  **Seamless Expansion:** Intelligently fill in the new, expanded areas of the canvas. The new content must seamlessly continue the existing scene, characters, lighting, and overall art style.
2.  **Preserve Original:** The content and quality of the original image area must be preserved perfectly. Do not alter or re-render the original pixels.
3.  **Contextual Awareness:** The original scene was about: "${originalPrompt}". Use this context to generate plausible and fitting extensions to the scene.
4.  **Aspect Ratio:** The final output image must strictly adhere to a ${newAspectRatio} aspect ratio.
`.trim();

    const parts = [
        { 
            inlineData: {
                data: base64Data,
                mimeType: mimeType,
            },
        },
        { text: fullPrompt },
    ];

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: {
                responseModalities: [Modality.IMAGE],
                imageConfig: {
                    aspectRatio: newAspectRatio,
                },
            },
        });

        const candidate = response.candidates?.[0];
        // The expanded image might be in the first or second part depending on the model's response structure.
        const imagePart = candidate?.content?.parts?.find(p => p.inlineData);

        if (imagePart && imagePart.inlineData) {
            const base64ImageBytes = imagePart.inlineData.data;
            return `data:${imagePart.inlineData.mimeType};base64,${base64ImageBytes}`;
        } else {
            if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
                 throw new Error(`Image expansion stopped unexpectedly. Reason: ${candidate.finishReason}.`);
            }
            throw new Error("No image data received from API for expansion.");
        }

    } catch (error) {
        console.error("Gemini API call failed during expansion:", error);
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("An unexpected error occurred while calling the Gemini API for expansion.");
    }
};
```

## components/ControlPanel.tsx

Added model selection dropdown between Image Style and Aspect Ratio, and included `model` in the generation settings.

```typescript
import React, { useState, useRef } from 'react';
import { CharacterUploader } from './CharacterUploader';
import { Character } from '../types';
import { downloadTextFile } from '../utils/fileUtils';

interface ControlPanelProps {
  onGenerate: (settings: { characters: Character[]; prompts: string[]; aspectRatio: string; imageStyle: string; model: string; }) => void;
  isLoading: boolean;
}

const initialCharacters: Character[] = Array.from({ length: 4 }, (_, i) => ({
  id: i + 1,
  name: `Character ${i + 1}`,
  file: null,
  previewUrl: null,
  mediaType: null,
  isSelected: false,
  referenceFrames: [],
  isProcessing: false,
  currentFrameIndex: 0,
}));

export const ControlPanel: React.FC<ControlPanelProps> = ({ onGenerate, isLoading }) => {
  const [characters, setCharacters] = useState<Character[]>(initialCharacters);
  const [imageStyle, setImageStyle] = useState('Match Reference');
  const [selectedModel, setSelectedModel] = useState('gemini-2.5-flash-image');
  const [aspectRatio, setAspectRatio] = useState('16:9');
  const [customAspectRatio, setCustomAspectRatio] = useState('');
  const [prompts, setPrompts] = useState('');
  const promptsTextareaRef = useRef<HTMLTextAreaElement>(null);
  const promptFileInputRef = useRef<HTMLInputElement>(null);
  const [copyButtonText, setCopyButtonText] = useState('คัดลอก');

  const handleCharacterUpdate = (updatedCharacter: Character) => {
    setCharacters(prev => prev.map(c => c.id === updatedCharacter.id ? updatedCharacter : c));
  };

  const handleInsertCharacterName = (name: string) => {
    const textarea = promptsTextareaRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const nameWithSpaces = `${name}`; // Insert name without extra spaces, user can add them.

    const newText = text.substring(0, start) + nameWithSpaces + text.substring(end);

    setPrompts(newText);

    setTimeout(() => {
        textarea.focus();
        textarea.selectionStart = textarea.selectionEnd = start + nameWithSpaces.length;
    }, 0);
  };

  const handleOpenFileClick = () => {
    promptFileInputRef.current?.click();
  };

  const handlePromptFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result;
      if (typeof text === 'string') {
        setPrompts(text);
      }
    };
    reader.onerror = () => {
      console.error("Failed to read file.");
      alert("Failed to read the prompt file.");
    }
    reader.readAsText(file);
    // Reset file input value to allow re-uploading the same file
    if(event.target) {
        event.target.value = '';
    }
  };

  const handleCopyPrompts = () => {
    if (!prompts || !navigator.clipboard) return;
    navigator.clipboard.writeText(prompts).then(() => {
      setCopyButtonText('คัดลอกแล้ว!');
      setTimeout(() => setCopyButtonText('คัดลอก'), 2000);
    }).catch(err => {
      console.error('Failed to copy text: ', err);
      alert('Failed to copy prompts.');
    });
  };

  const handleSavePrompts = () => {
    if (!prompts) return;
    downloadTextFile(prompts, 'prompts.txt');
  };

  const handleClearPrompts = () => {
    setPrompts('');
  };

  const handleGenerateClick = () => {
    const finalAspectRatio = aspectRatio === 'Custom' ? customAspectRatio : aspectRatio;
    // Split prompts by new line only, allowing commas inside the prompt text.
    const promptList = prompts.split('\n').map(p => p.trim()).filter(p => p);
    onGenerate({ characters, prompts: promptList, aspectRatio: finalAspectRatio, imageStyle, model: selectedModel });
  };

  return (
    <div className="bg-gray-800 p-6 rounded-lg shadow-lg flex flex-col gap-6">
      <input
        type="file"
        ref={promptFileInputRef}
        onChange={handlePromptFileChange}
        accept=".txt"
        className="hidden"
      />
      <div>
        <h2 className="text-xl font-semibold mb-1 border-b border-gray-700 pb-2">Character References</h2>
        <p className="text-xs text-gray-400 mb-4">Upload an image or a short video (under 10s) for each character.</p>
        <div className="grid grid-cols-2 gap-4">
          {characters.map(character => (
            <CharacterUploader 
              key={character.id} 
              character={character} 
              onUpdate={handleCharacterUpdate}
              onInsertName={handleInsertCharacterName}
            />
          ))}
        </div>
      </div>

      <div>
        <label htmlFor="image-style" className="block text-lg font-semibold mb-2">Image Style</label>
        <select
          id="image-style"
          value={imageStyle}
          onChange={(e) => setImageStyle(e.target.value)}
          className="w-full p-2 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
        >
          <option value="Match Reference">Match Reference Style</option>
          <option value="Cartoon">Cartoon</option>
          <option value="Disney Cartoon">Disney Cartoon</option>
          <option value="ลายไทย">ลายไทย</option>
          <option value="Anime / Manga">Anime / Manga</option>
          <option value="Realistic">Realistic</option>
          <option value="Fantasy Art">Fantasy Art</option>
          <option value="Pixel Art">Pixel Art</option>
          <option value="Watercolor">Watercolor</option>
          <option value="Black & White (Laser Printer)">Black &amp; White (Laser Printer)</option>
        </select>
        <p className="text-xs text-gray-400 mt-1">'Match Reference' will try to replicate the style of your uploaded images.</p>
      </div>

      <div>
        <label htmlFor="model-select" className="block text-lg font-semibold mb-2">Model</label>
        <select
          id="model-select"
          value={selectedModel}
          onChange={(e) => setSelectedModel(e.target.value)}
          className="w-full p-2 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
        >
          <option value="gemini-2.5-flash-image">Gemini 2.5 Flash (Fast)</option>
          <option value="gemini-3-pro-image-preview">Gemini 3 Pro (High Quality)</option>
        </select>
        <p className="text-xs text-gray-400 mt-1">Select the AI model for generation.</p>
      </div>

      <div>
        <label htmlFor="aspect-ratio" className="block text-lg font-semibold mb-2">Aspect Ratio</label>
        <select
          id="aspect-ratio"
          value={aspectRatio}
          onChange={(e) => setAspectRatio(e.target.value)}
          className="w-full p-2 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
        >
          <option>16:9</option>
          <option>9:16</option>
          <option>1:1</option>
          <option>4:3</option>
          <option>Custom</option>
        </select>
        {aspectRatio === 'Custom' && (
          <input
            type="text"
            placeholder="e.g., 21:9"
            value={customAspectRatio}
            onChange={(e) => setCustomAspectRatio(e.target.value)}
            className="w-full mt-2 p-2 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
          />
        )}
      </div>

      <div>
        <div className="flex justify-between items-center mb-2">
          <label htmlFor="prompts" className="block text-lg font-semibold">Prompt List (up to 10)</label>
          <div className="flex items-center gap-2">
            <button
              onClick={handleOpenFileClick}
              disabled={isLoading}
              className="px-2 py-1 text-xs bg-gray-700 text-gray-300 rounded hover:bg-red-600 hover:text-white disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed transition-colors"
              title="Open prompts from a .txt file"
            >
              เปิด
            </button>
            <button 
              onClick={handleCopyPrompts}
              disabled={!prompts || isLoading}
              className="px-2 py-1 text-xs bg-gray-700 text-gray-300 rounded hover:bg-red-600 hover:text-white disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed transition-colors"
              title="Copy all prompts to clipboard"
            >
              {copyButtonText}
            </button>
            <button 
              onClick={handleSavePrompts}
              disabled={!prompts || isLoading}
              className="px-2 py-1 text-xs bg-gray-700 text-gray-300 rounded hover:bg-red-600 hover:text-white disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed transition-colors"
              title="Save prompts to a .txt file"
            >
              บันทึก
            </button>
            <button 
              onClick={handleClearPrompts}
              disabled={!prompts || isLoading}
              className="px-2 py-1 text-xs bg-gray-700 text-gray-300 rounded hover:bg-red-800 hover:text-white disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed transition-colors"
              title="Clear all prompts"
            >
              ล้าง
            </button>
          </div>
        </div>
        <textarea
          id="prompts"
          ref={promptsTextareaRef}
          rows={10}
          value={prompts}
          onChange={(e) => setPrompts(e.target.value)}
          placeholder="Character 1 running in the park&#10;Character 1 and Character 2 eating ice cream&#10;Character 1 flying over the city"
          className="w-full p-3 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500 placeholder-gray-500"
        />
        <p className="text-xs text-gray-400 mt-1">Separate each prompt with a new line. (Commas are treated as text).</p>
      </div>

      <button
        onClick={handleGenerateClick}
        disabled={isLoading}
        className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 px-4 rounded-lg transition-all duration-300 ease-in-out disabled:bg-red-900 disabled:cursor-not-allowed flex items-center justify-center text-lg shadow-lg transform hover:scale-105 disabled:scale-100"
      >
        {isLoading ? (
          <>
            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            Generating...
          </>
        ) : (
          'Generate All Images'
        )}
      </button>
    </div>
  );
};
```

## App.tsx

Passed the selected model from `handleGenerate` settings to the `generateStoryImage` function.

```typescript
import React, { useState, useCallback } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { ResultsDisplay } from './components/ResultsDisplay';
import { Character, GeneratedImage } from './types';
import { generateStoryImage, expandImage } from './services/geminiService';
import { getFormattedDate } from './utils/fileUtils';
import { ExpandModal } from './components/ExpandModal';

function App() {
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [previewImageUrl, setPreviewImageUrl] = useState<string | null>(null);
  const [expandingImage, setExpandingImage] = useState<GeneratedImage | null>(null);
  const [isExpanding, setIsExpanding] = useState(false);

  const handleGenerate = useCallback(async (settings: {
    characters: Character[];
    prompts: string[];
    aspectRatio: string;
    imageStyle: string;
    model: string;
  }) => {
    const { characters, prompts, aspectRatio, imageStyle, model } = settings;

    if (prompts.length === 0 || prompts[0].trim() === '') {
        setError("Please enter at least one prompt.");
        return;
    }

    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    const selectedCharacters = characters.filter(c => c.isSelected && c.file);
    const dateStr = getFormattedDate();

    for (let i = 0; i < prompts.length; i++) {
      const prompt = prompts[i];
      if (!prompt.trim()) continue;

      try {
        const imageDataUrl = await generateStoryImage(prompt, selectedCharacters, aspectRatio, imageStyle, model);
        const filename = `${String(i + 1).padStart(3, '0')}_${dateStr}.png`;

        setGeneratedImages(prev => [
          ...prev,
          { id: self.crypto.randomUUID(), imageDataUrl, prompt, filename }
        ]);
      } catch (e) {
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred.';
        setError(`Failed to generate image for prompt "${prompt}": ${errorMessage}. Please check your API key and try again.`);
        break; 
      }
    }

    setIsLoading(false);
  }, []);

  const handleExpandRequest = useCallback((image: GeneratedImage) => {
    setExpandingImage(image);
  }, []);

  const handleCloseExpandModal = useCallback(() => {
    if (!isExpanding) {
      setExpandingImage(null);
    }
  }, [isExpanding]);

  const handleConfirmExpand = useCallback(async (newAspectRatio: string) => {
    if (!expandingImage) return;

    setIsExpanding(true);
    setError(null);
    const originalImage = expandingImage;

    try {
      const newImageDataUrl = await expandImage(originalImage.imageDataUrl, newAspectRatio, originalImage.prompt);
      const dateStr = getFormattedDate();

      const newImage: GeneratedImage = {
        id: self.crypto.randomUUID(),
        imageDataUrl: newImageDataUrl,
        prompt: `Expanded to ${newAspectRatio} from: "${originalImage.prompt}"`,
        filename: `${originalImage.filename.split('.png')[0]}_expanded_${newAspectRatio.replace(':', 'x')}.png`
      };

      setGeneratedImages(prevImages => {
        const originalIndex = prevImages.findIndex(img => img.id === originalImage.id);
        if (originalIndex === -1) {
          return [...prevImages, newImage]; // Failsafe if original is somehow not found
        }
        const newImages = [...prevImages];
        newImages.splice(originalIndex + 1, 0, newImage);
        return newImages;
      });
      setExpandingImage(null); // Close modal on success
    } catch (e) {
      console.error(e);
      const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred during expansion.';
      setError(`Failed to expand image: ${errorMessage}`);
      setExpandingImage(null); // Close modal on error
    } finally {
      setIsExpanding(false);
    }
  }, [expandingImage]);


  const handlePreview = useCallback((imageUrl: string) => {
    setPreviewImageUrl(imageUrl);
  }, []);

  const closePreview = () => {
    setPreviewImageUrl(null);
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-200 font-sans">
      <header className="py-4 px-8 bg-gray-800/50 backdrop-blur-sm border-b border-gray-700 sticky top-0 z-10">
        <h1 className="text-2xl font-bold text-center text-transparent bg-clip-text bg-gradient-to-r from-red-500 to-yellow-500">
          Consistent AI Character Story Creator
        </h1>
      </header>

      <main className="flex flex-col lg:flex-row gap-8 p-4 md:p-8">
        <div className="lg:w-1/3 xl:w-1/4 lg:sticky lg:top-24 self-start">
          <ControlPanel onGenerate={handleGenerate} isLoading={isLoading} />
        </div>

        <div className="flex-1">
          <ResultsDisplay 
            images={generatedImages} 
            isLoading={isLoading} 
            error={error} 
            onPreview={handlePreview}
            onExpand={handleExpandRequest}
          />
        </div>
      </main>

      {previewImageUrl && (
        <div 
          className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 backdrop-blur-sm"
          onClick={closePreview}
        >
          <div className="relative" onClick={(e) => e.stopPropagation()}>
            <img src={previewImageUrl} alt="Generated preview" className="max-w-[90vw] max-h-[90vh] object-contain rounded-lg shadow-2xl"/>
            <button 
              onClick={closePreview}
              className="absolute -top-4 -right-4 bg-white text-black rounded-full h-10 w-10 flex items-center justify-center text-2xl font-bold hover:bg-red-500 hover:text-white transition-transform transform hover:scale-110"
              aria-label="Close preview"
            >
              &times;
            </button>
          </div>
        </div>
      )}

      {expandingImage && (
        <ExpandModal
          image={expandingImage}
          onClose={handleCloseExpandModal}
          onExpand={handleConfirmExpand}
          isLoading={isExpanding}
        />
      )}
    </div>
  );
}

export default App;

