import { GoogleGenAI, Modality } from "@google/genai";
import { Character } from '../types';
import { fileToBase64 } from "../utils/fileUtils";

export const generateStoryImage = async (
    prompt: string, 
    characters: Character[], 
    aspectRatio: string, 
    imageStyle: string,
    model: string = 'gemini-2.5-flash-image'
): Promise<string> => {

    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const characterNames = characters.map(c => c.name).join(' and ');

    let styleDirective = '';
    if (imageStyle === 'Match Reference') {
      styleDirective = 'The overall artistic style (e.g., cartoon, anime, realistic) must perfectly match the reference images.';
    } else if (imageStyle === 'Black & White (Laser Printer)') {
      styleDirective = 'The artistic style must be a high-contrast, clean black and white line art, specifically optimized for printing on a monochrome laser printer. Use solid blacks and whites and avoid shades of gray to ensure maximum clarity and print quality. The character\'s core features must still strictly match the reference images.';
    } else {
      styleDirective = `The overall artistic style must be **${imageStyle}**, while ensuring the character's core features (face, hair, etc.) strictly match the reference images to maintain consistency.`;
    }

    const fullPrompt = `
**Objective:** Create a visually consistent, high-resolution 4K image for a story sequence using the provided reference images/frames.

**Scene Description:**
${prompt}

**Characters Involved:**
${characterNames}

**Core Directives (Strictly follow):**

1.  **UNWAVERING CHARACTER CONSISTENCY (HIGHEST PRIORITY):**
    *   **Multiple References Provided:** You are given multiple reference images for each character to capture their appearance from various angles.
    *   **Face & Features:** The character's face, eyes, nose, mouth, and all facial features MUST be an exact, consistent match derived from the provided reference frames. Synthesize a coherent 3D understanding of the face from all frames.
    *   **Hairstyle & Color:** Replicate the exact hairstyle and color from the references.
    *   **Clothing & Attire:** The character's outfit MUST remain consistent with the reference images unless the prompt explicitly asks for a change.
    *   **Art Style:** ${styleDirective}

2.  **SCENE & BACKGROUND CONTINUITY:**
    *   Render the scene based on the description above.
    *   Maintain a consistent artistic style for the background and environment to ensure it feels like the same world across different images.

3.  **Technical Specifications:**
    *   **Aspect Ratio:** Strictly adhere to a ${aspectRatio} aspect ratio.

**Final Check:** Before finalizing, verify that the characters in the generated image are indistinguishable from their composite reference images.
`.trim();

    try {
        // Special handling for Imagen models
        if (model.includes('imagen')) {
            // Imagen models via this SDK generateImages method do not support the same multimodal parts injection 
            // as Gemini. We must use the prompt only.

            // Construct a prompt that describes the scene and style, but acknowledge we can't pass the image data directly.
            const imagenPrompt = `
            Scene: ${prompt}. 
            Characters: ${characterNames}.
            Style: ${imageStyle === 'Match Reference' ? 'High quality, detailed' : imageStyle}.
            Aspect Ratio: ${aspectRatio}.
            `.trim();

            const response = await ai.models.generateImages({
                model,
                prompt: imagenPrompt,
                config: {
                    numberOfImages: 1,
                    aspectRatio: aspectRatio,
                    outputMimeType: 'image/jpeg',
                },
            });

            if (response.generatedImages && response.generatedImages.length > 0) {
                 const base64ImageBytes = response.generatedImages[0].image.imageBytes;
                 // Imagen usually returns JPEG by default or what is specified
                 return `data:image/jpeg;base64,${base64ImageBytes}`;
            } else {
                throw new Error("No image data received from Imagen API.");
            }

        } else {
            // Standard Gemini Multimodal Generation
            const parts: any[] = [{ text: fullPrompt }];

            for (const character of characters) {
                if (character.referenceFrames.length > 0) {
                    for (const frame of character.referenceFrames) {
                        parts.push({
                            inlineData: {
                                data: frame.data,
                                mimeType: frame.mimeType,
                            },
                        });
                    }
                }
            }

            const response = await ai.models.generateContent({
                model,
                contents: { parts },
                config: {
                    responseModalities: [Modality.IMAGE],
                    imageConfig: {
                        aspectRatio: aspectRatio,
                    },
                },
            });

            const candidate = response.candidates?.[0];
            const firstPart = candidate?.content?.parts?.[0];

            if (firstPart && firstPart.inlineData) {
                const base64ImageBytes = firstPart.inlineData.data;
                return `data:${firstPart.inlineData.mimeType};base64,${base64ImageBytes}`;
            } else {
                if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
                    throw new Error(`Image generation stopped unexpectedly. Reason: ${candidate.finishReason}. Please check your prompt for safety violations.`);
                }
                throw new Error("No image data received from API. The prompt might be too complex or the response was empty.");
            }
        }

    } catch (error) {
        console.error("Gemini API call failed:", error);
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("An unexpected error occurred while calling the Gemini API.");
    }
};

export const expandImage = async (imageDataUrl: string, newAspectRatio: string, originalPrompt: string): Promise<string> => {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-2.5-flash-image';

    const [header, base64Data] = imageDataUrl.split(',');
    if (!header || !base64Data) {
        throw new Error("Invalid imageDataUrl format");
    }
    const mimeType = header.match(/:(.*?);/)?.[1] || 'image/png';

    const fullPrompt = `
**Objective:** You are an expert image editor AI. Your task is to expand the given image to a new aspect ratio of **${newAspectRatio}**.

**Core Directives (Strictly follow):**
1.  **Seamless Expansion:** Intelligently fill in the new, expanded areas of the canvas. The new content must seamlessly continue the existing scene, characters, lighting, and overall art style.
2.  **Preserve Original:** The content and quality of the original image area must be preserved perfectly. Do not alter or re-render the original pixels.
3.  **Contextual Awareness:** The original scene was about: "${originalPrompt}". Use this context to generate plausible and fitting extensions to the scene.
4.  **Aspect Ratio:** The final output image must strictly adhere to a ${newAspectRatio} aspect ratio.
`.trim();

    const parts = [
        { 
            inlineData: {
                data: base64Data,
                mimeType: mimeType,
            },
        },
        { text: fullPrompt },
    ];

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: {
                responseModalities: [Modality.IMAGE],
                imageConfig: {
                    aspectRatio: newAspectRatio,
                },
            },
        });

        const candidate = response.candidates?.[0];
        const imagePart = candidate?.content?.parts?.find(p => p.inlineData);

        if (imagePart && imagePart.inlineData) {
            const base64ImageBytes = imagePart.inlineData.data;
            return `data:${imagePart.inlineData.mimeType};base64,${base64ImageBytes}`;
        } else {
            if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
                 throw new Error(`Image expansion stopped unexpectedly. Reason: ${candidate.finishReason}.`);
            }
            throw new Error("No image data received from API for expansion.");
        }

    } catch (error) {
        console.error("Gemini API call failed during expansion:", error);
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("An unexpected error occurred while calling the Gemini API for expansion.");
    }
};

