      const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred while adding frame.';
      setError(`Failed to add frame: ${errorMessage}`);
    } finally {
      setIsLoading(false);
    }
  }, []);


  const handlePreview = useCallback((imageUrl: string) => {
