// Utility to handle Google Drive Picker interactions

const SCOPES = 'https://www.googleapis.com/auth/drive.readonly';
const DISCOVERY_DOCS = ['https://www.googleapis.com/discovery/v1/apis/drive/v3/rest'];

let gapiLoaded = false;
let gisLoaded = false;

const loadScript = (src: string): Promise<void> => {
  return new Promise((resolve, reject) => {
    if (document.querySelector(`script[src="${src}"]`)) {
      resolve();
      return;
    }
    const script = document.createElement('script');
    script.src = src;
    script.async = true;
    script.defer = true;
    script.onload = () => resolve();
    script.onerror = () => reject(new Error(`Failed to load script: ${src}`));
    document.body.appendChild(script);
  });
};

export const initializeGoogleDrive = async (): Promise<void> => {
  try {
    await Promise.all([
      loadScript('https://apis.google.com/js/api.js'),
      loadScript('https://accounts.google.com/gsi/client'),
    ]);

    await new Promise<void>((resolve) => {
      window.gapi.load('client:picker', async () => {
        await window.gapi.client.init({
            discoveryDocs: DISCOVERY_DOCS,
        });
        gapiLoaded = true;
        resolve();
      });
    });

    gisLoaded = true;
  } catch (error) {
    console.error('Error initializing Google Drive API:', error);
    throw error;
  }
};

export const openGoogleDrivePicker = async (apiKey: string): Promise<File | null> => {
  if (!gapiLoaded || !gisLoaded) {
    await initializeGoogleDrive();
  }

  // Ideally, CLIENT_ID should be in process.env.GOOGLE_CLIENT_ID. 
  // Since we can't enforce that in this environment, we check or ask.
  let clientId = process.env.GOOGLE_CLIENT_ID;

  if (!clientId) {
      // Fallback for demo purposes: try to ask user or alert
      const input = prompt("Google Drive integration requires a Client ID. Please enter your Google Cloud Client ID:");
      if (input) clientId = input;
      else throw new Error("Google Cloud Client ID is required to use Google Drive.");
  }

  return new Promise((resolve, reject) => {
    const tokenClient = window.google.accounts.oauth2.initTokenClient({
      client_id: clientId!,
      scope: SCOPES,
      callback: async (response: any) => {
        if (response.error !== undefined) {
          reject(response);
          return;
        }
        createPicker(response.access_token);
      },
    });

    // Request an access token
    tokenClient.requestAccessToken();

    const createPicker = (accessToken: string) => {
      const picker = new window.google.picker.PickerBuilder()
        .addView(window.google.picker.ViewId.DOCS) // Docs view (includes images/videos)
        .setOAuthToken(accessToken)
        .setDeveloperKey(apiKey)
        .setCallback(async (data: any) => {
          if (data.action === window.google.picker.Action.PICKED) {
            const doc = data.docs[0];
            const fileId = doc.id;
            const mimeType = doc.mimeType;
            const name = doc.name;

            try {
                // We must download the file content to pass it to the rest of the app
                // using the Google Drive API directly via gapi client
                const fileResponse = await window.gapi.client.drive.files.get({
                    fileId: fileId,
                    alt: 'media',
                }, { responseType: 'blob' }); // Important for binary data

                // gapi client returns the body in .body (string) or we need to handle blob
                // However, gapi.client request returns a result object.
                // For binary download, it's often easier to use fetch with the token.

                const blob = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
                    headers: {
                        'Authorization': `Bearer ${accessToken}`
                    }
                }).then(res => res.blob());

                const file = new File([blob], name, { type: mimeType });
                resolve(file);

            } catch (e) {
                console.error("Error downloading file from Drive:", e);
                reject(new Error("Failed to download selected file from Google Drive."));
            }
          } else if (data.action === window.google.picker.Action.CANCEL) {
            resolve(null);
          }
        })
        .build();
      picker.setVisible(true);
    };
  });
};
