          throw new Error("Google Cloud Client ID is required to use Google Drive.");
      }
  }

  return new Promise((resolve, reject) => {
    const tokenClient = (window as any).google.accounts.oauth2.initTokenClient({
      client_id: clientId!,
      scope: SCOPES,
      callback: async (response: any) => {
        if (response.error !== undefined) {
          // If the error is related to invalid client_id, clear it from local storage so user can try again
          if (response.error.includes('client_id')) {
              localStorage.removeItem('GOOGLE_CLIENT_ID');
              reject(new Error("Invalid Client ID. Please try again."));
          } else {
              reject(response);
          }
          return;
        }
        createPicker(response.access_token);
      },
    });

    // Request an access token
    tokenClient.requestAccessToken();

    const createPicker = (accessToken: string) => {
      const picker = new (window as any).google.picker.PickerBuilder()
        .addView((window as any).google.picker.ViewId.DOCS) // Docs view (includes images/videos)
        .setOAuthToken(accessToken)
        .setDeveloperKey(apiKey)
        .setCallback(async (data: any) => {
          if (data.action === (window as any).google.picker.Action.PICKED) {
            const doc = data.docs[0];
            const fileId = doc.id;
            const mimeType = doc.mimeType;
            const name = doc.name;

            try {
                // We must download the file content to pass it to the rest of the app
                // using the Google Drive API directly via gapi client
                // or simply fetch with auth header since we have the token.

                const response = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
                    headers: {
                        'Authorization': `Bearer ${accessToken}`
                    }
                });

                if (!response.ok) throw new Error('Network response was not ok');

                const blob = await response.blob();
                const file = new File([blob], name, { type: mimeType });
                resolve(file);

            } catch (e) {
                console.error("Error downloading file from Drive:", e);
                reject(new Error("Failed to download selected file from Google Drive."));
            }
          } else if (data.action === (window as any).google.picker.Action.CANCEL) {
            resolve(null);
          }
        })
        .build();
      picker.setVisible(true);
    };
  });
};

