    await initializeGoogleDrive();
  }

  // Check environment variable first, then local storage
  let clientId = process.env.GOOGLE_CLIENT_ID || localStorage.getItem('GOOGLE_CLIENT_ID');

  if (!clientId) {
      // Fallback: Ask user and save to local storage for future use
      const input = prompt("Google Drive integration requires a Google Cloud Client ID.\n\nPlease enter your Client ID (it will be saved in your browser):");
      if (input && input.trim()) {
