```tsx
import React, { useRef, useState, useEffect } from 'react';
import { Character } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';
import { SpinnerIcon } from './icons/SpinnerIcon';
import { FilmIcon } from './icons/FilmIcon';
import { GoogleDriveIcon } from './icons/GoogleDriveIcon';
import { DevicePhoneIcon } from './icons/DevicePhoneIcon';
import { extractFramesFromVideo } from '../utils/videoUtils';
import { fileToBase64 } from '../utils/fileUtils';
import { openGoogleDrivePicker, saveClientId } from '../utils/googleDriveUtils';
import { GoogleClientIdModal } from './GoogleClientIdModal';

interface CharacterUploaderProps {
  character: Character;
  onUpdate: (character: Character) => void;
  onInsertName: (name: string) => void;
}

export const CharacterUploader: React.FC<CharacterUploaderProps> = ({ character, onUpdate, onInsertName }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showClientIdModal, setShowClientIdModal] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const processFile = async (file: File) => {
      const mediaType = file.type.startsWith('video/') ? 'video' : 'image';

      // Revoke previous object URL if it exists
      if (character.previewUrl) {
        URL.revokeObjectURL(character.previewUrl);
      }

      // Create a temporary URL for processing
      const tempUrl = URL.createObjectURL(file);

      onUpdate({
        ...character,
        isProcessing: true,
        file,
        mediaType,
        previewUrl: tempUrl,
        currentFrameIndex: 0,
      });

      try {
        let frames: { data: string; mimeType: string; }[] = [];
        if (mediaType === 'video') {
          frames = await extractFramesFromVideo(file);
          // Important: Revoke the video URL immediately after extraction to free system resources
          URL.revokeObjectURL(tempUrl);

          onUpdate({
            ...character,
            file, 
            mediaType,
            previewUrl: null,
            isSelected: true,
            referenceFrames: frames,
            isProcessing: false,
            currentFrameIndex: 0,
          });
        } else {
          const base64Data = await fileToBase64(file);
          frames = [{ data: base64Data, mimeType: file.type }];
          URL.revokeObjectURL(tempUrl);

           onUpdate({
            ...character,
            file, 
            mediaType,
            previewUrl: null,
            isSelected: true,
            referenceFrames: frames,
            isProcessing: false,
            currentFrameIndex: 0,
          });
        }

      } catch(error) {
        console.error("Error processing file:", error);
        alert(error instanceof Error ? error.message : "Failed to process file.");
        handleRemoveMedia(); // Revert on error
      }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
    setIsMenuOpen(false);
  };

  const launchDrivePicker = async () => {
    try {
        if (!process.env.API_KEY) {
            alert("API Key is missing. Cannot access Google Drive.");
            return;
        }
        const file = await openGoogleDrivePicker(process.env.API_KEY);
        if (file) {
            await processFile(file);
        }
    } catch (error: any) {
        console.error("Drive Picker Error:", error);
        if (error.message === 'MISSING_CLIENT_ID' || error.message === 'INVALID_CLIENT_ID') {
            setShowClientIdModal(true);
        } else {
            alert(`Failed to pick file from Drive: ${error.message || 'Unknown error'}`);
        }
    }
  };

  const handleDriveSelect = async () => {
    setIsMenuOpen(false);
    await launchDrivePicker();
  };

  const handleSaveClientId = async (clientId: string) => {
      saveClientId(clientId);
      setShowClientIdModal(false);
      // Retry immediately
      await launchDrivePicker();
  };

  const handleRemoveMedia = () => {
    if (character.previewUrl) {
      URL.revokeObjectURL(character.previewUrl);
    }
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
    onUpdate({
      ...character,
      file: null,
      previewUrl: null,
      mediaType: null,
      isSelected: false,
      referenceFrames: [],
      isProcessing: false,
      currentFrameIndex: 0,
    });
  };

  const handleNextFrame = (e: React.MouseEvent) => {
    e.stopPropagation();
    const totalFrames = character.referenceFrames.length;
    if (totalFrames <= 1) return;
    const nextIndex = (character.currentFrameIndex + 1) % totalFrames;
    onUpdate({ ...character, currentFrameIndex: nextIndex });
  };

  // Determine the source to display
  const displaySrc = character.previewUrl 
    ? character.previewUrl
    : (character.referenceFrames.length > 0 
        ? `data:${character.referenceFrames[character.currentFrameIndex].mimeType};base64,${character.referenceFrames[character.currentFrameIndex].data}`
        : null);

  const hasMultipleFrames = character.referenceFrames.length > 1;

  const handleMainClick = () => {
      if (!character.isProcessing && !displaySrc) {
          setIsMenuOpen(!isMenuOpen);
      }
  };

  return (
    <div className="flex flex-col gap-2" ref={containerRef}>
      {showClientIdModal && (
          <GoogleClientIdModal 
            onSave={handleSaveClientId} 
            onCancel={() => setShowClientIdModal(false)} 
          />
      )}

      <div 
        className="relative aspect-square w-full bg-gray-700 rounded-md flex items-center justify-center cursor-pointer border-2 border-dashed border-gray-500 hover:border-red-500 transition-colors group overflow-hidden"
        onClick={handleMainClick}
        title={hasMultipleFrames ? "Click right side to cycle frames" : "Upload media"}
      >
