import React, { useState, useRef, useEffect } from 'react';
import { useApiKeyContext } from '../../context/ApiKeyContext';

interface ApiKeyManagerProps {
  onApiKeyChange?: (apiKey: string) => void;
}

const ApiKeyManager: React.FC<ApiKeyManagerProps> = ({ onApiKeyChange }) => {
  const { apiKey, setApiKey, sendApiKey, clearApiKey, hasApiKey, loadApiKey } = useApiKeyContext();
  const inputRef = useRef<HTMLInputElement>(null);
  const [isFocused, setIsFocused] = useState(false);

  useEffect(() => {
    loadApiKey();
  }, [loadApiKey]);

  const handleSend = async () => {
    sendApiKey(apiKey);
    if (onApiKeyChange) {
      onApiKeyChange(apiKey);
    }
  };

  const handleCopy = () => {
    if (apiKey) {
      navigator.clipboard.writeText(apiKey);
      console.log('API key copied!');
    } else {
      console.log('No API key to copy.');
    }
  };

  const handleClear = () => {
    clearApiKey();
  };

  const handleFocus = () => {
    setIsFocused(true);
  };

  const handleBlur = () => {
    setIsFocused(false);
  };

  return (
    <div className="flex flex-col gap-2 p-2">
      <div className="flex items-center gap-2">
        <label htmlFor="api-key" className="text-sm text-gray-400">API Key:</label>
           <button onClick={handleSend} className="px-2 py-0.5 text-[10px] bg-gray-800 hover:bg-gray-700 text-gray-400 rounded border border-gray-700 transition-colors">Send</button>
           <button onClick={handleCopy} className="px-2 py-0.5 text-[10px] bg-gray-800 hover:bg-gray-700 text-gray-400 rounded border border-gray-700 transition-colors">Copy</button>
           <button onClick={handleClear} className="px-2 py-0.5 text-[10px] bg-gray-800 hover:bg-gray-700 text-gray-400 rounded border border-gray-700 transition-colors">Clear</button>
        </div>
      </div>

      <input
        ref={inputRef}
        type="text"
        value={apiKey}
        onChange={(e) => setApiKey(e.target.value)}
        onFocus={handleFocus}
        onBlur={handleBlur}
        className="flex-1 bg-gray-900/50 border border-gray-800 rounded px-2 py-1 text-xs font-mono text-green-500 w-full outline-none focus:border-red-500/50 transition-colors"
        placeholder="Enter your Gemini API key..."
      />

      <div className="hidden sm:flex items-center gap-2">
        <button 
          onClick={handleSend}
          className="px-3 py-1 text-xs font-bold bg-red-600 hover:bg-red-700 text-white rounded shadow-sm transition-all active:scale-95"
        >
          Send
        </button>
      </div>
    </div>
  );
};

export default ApiKeyManager;
