import React, { useState, useEffect, useRef } from 'react';

export const ApiKeyManager: React.FC = () => {
  const [apiKey, setApiKey] = useState<string>('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Ensure process.env.API_KEY is available globally even if not defined by the environment
    if (typeof window.process === 'undefined') {
      (window as any).process = { env: {} };
    }

    const storedKey = localStorage.getItem('gemini_api_key');
    const envKey = process.env.API_KEY;

    // Logic to initialize the key
    if (envKey && envKey !== 'undefined' && envKey !== '') {
      setApiKey(envKey);
    } else if (storedKey && storedKey !== '') {
      process.env.API_KEY = storedKey;
      setApiKey(storedKey);
    } else {
      setApiKey('no API key');
    }
  }, []);

  const handleSend = () => {
    const value = apiKey.trim();
    if (value && value !== 'no API key' && value !== '') {
      process.env.API_KEY = value;
      localStorage.setItem('gemini_api_key', value);
      alert('API key updated and saved to localStorage.');
    } else {
      alert('Please enter a valid API key.');
    }
  };

  const handleCopy = () => {
    if (apiKey && apiKey !== 'no API key' && apiKey !== '') {
      navigator.clipboard.writeText(apiKey).then(() => {
        alert('API key copied to clipboard.');
      }).catch(err => {
        console.error('Failed to copy: ', err);
      });
    }
  };

  const handleClear = () => {
    setApiKey('');
    localStorage.removeItem('gemini_api_key');
    process.env.API_KEY = '';
    if (inputRef.current) inputRef.current.focus();
  };

  const handleFocus = () => {
    if (apiKey === 'no API key') {
      setApiKey('');
    }
  };

  const handleBlur = () => {
    if (apiKey.trim() === '') {
      setApiKey('no API key');
    }
  };

  return (
    <div className="w-full bg-black border-b border-gray-800 px-4 py-1.5 flex flex-col sm:flex-row items-center gap-3 z-[100] sticky top-0">
