          API key :
        </label>
      </div>

      <div className="flex-1 w-full relative">
        <input
          ref={inputRef}
          type="text"
          value={apiKey}
          onChange={(e) => setApiKey(e.target.value)}
          onFocus={handleFocus}
          onBlur={handleBlur}
          spellCheck={false}
          className="w-full bg-gray-900/40 border border-gray-800 rounded px-3 py-1 text-xs font-mono text-green-500 focus:outline-none focus:border-red-500/50 transition-colors placeholder-gray-700"
          placeholder="Enter your Gemini API key..."
        />
      </div>

      <div className="flex items-center gap-2">
