import { GoogleGenAI } from "@google/genai";
import { Character } from '../types';

export const generateStoryImage = async (
    prompt: string, 
    characters: Character[], 
    aspectRatio: string, 
    imageStyle: string,
    model: string = 'gemini-2.5-flash-image'
): Promise<string> => {

    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }

    // Initialize the client inside the function to ensure it uses the latest API key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const characterNames = characters.map(c => c.name).join(' and ');

    let styleDirective = '';
    if (imageStyle === 'Match Reference') {
      styleDirective = 'The overall artistic style (e.g., cartoon, anime, realistic) must perfectly match the reference images provided.';
    } else if (imageStyle === 'Black & White (Laser Printer)') {
      styleDirective = 'The artistic style must be a high-contrast, clean black and white line art, specifically optimized for printing on a monochrome laser printer. Use solid blacks and whites and avoid shades of gray. Maintain character identity but convert them into this line-art style.';
    } else {
      styleDirective = `The overall artistic style must be **${imageStyle}**. **CRITICAL INSTRUCTION:** You must translate the character's appearance from the reference images into this **${imageStyle}** style. Do not simply copy the art style of the reference images if it differs from ${imageStyle}. Keep the facial features and identity recognizable, but rendered in ${imageStyle}.`;
    }

    const fullPrompt = `
**Objective:** Create a high-resolution 4K image based on the description and references below.

**1. TARGET ARTISTIC STYLE (HIGHEST PRIORITY):**
${styleDirective}

**2. SCENE DESCRIPTION:**
${prompt}

**3. CHARACTERS:**
*   **Characters Involved:** ${characterNames}
*   **Identity & Consistency:** Use the provided reference images to strictly maintain the facial features, identity, hairstyle, and outfit of the characters.
*   **Style Adaptation:** **Apply the Target Artistic Style defined in Section 1 to these characters.** For example, if the style is 'Pixel Art', the characters must be rendered as Pixel Art, even if the reference image is a photograph.

**4. BACKGROUND:**
*   Ensure the background matches the scene description and the Target Artistic Style seamlessly.

**5. TECHNICAL:**
*   **Aspect Ratio:** ${aspectRatio}

**Final Check:** Ensure the result looks like a cohesive piece of art in the requested **${imageStyle}** style, featuring the specific characters described.
`.trim();

    try {
        // Special handling for Imagen models
        if (model.includes('imagen')) {
            const imagenPrompt = `
            Scene: ${prompt}. 
            Characters: ${characterNames}.
            Style: ${imageStyle === 'Match Reference' ? 'High quality, detailed' : imageStyle}.
            Aspect Ratio: ${aspectRatio}.
            `.trim();

            const response = await ai.models.generateImages({
                model,
                prompt: imagenPrompt,
                config: {
                    numberOfImages: 1,
                    aspectRatio: aspectRatio,
                    outputMimeType: 'image/jpeg',
                },
            });

            if (response.generatedImages && response.generatedImages.length > 0) {
                 const base64ImageBytes = response.generatedImages[0].image.imageBytes;
                 return `data:image/jpeg;base64,${base64ImageBytes}`;
            } else {
                throw new Error("No image data received from Imagen API.");
            }

        } else {
            // Standard Gemini Multimodal Generation
            const parts: any[] = [{ text: fullPrompt }];

            for (const character of characters) {
                if (character.referenceFrames.length > 0) {
                    for (const frame of character.referenceFrames) {
                        parts.push({
                            inlineData: {
                                data: frame.data,
                                mimeType: frame.mimeType,
                            },
                        });
                    }
                }
            }

            const config: any = {
                imageConfig: {
                    aspectRatio: aspectRatio,
                },
            };
            // Add imageSize if using high-quality Gemini 3 Pro model
            if (model === 'gemini-3-pro-image-preview') {
                config.imageConfig.imageSize = '1K';
            }

            const response = await ai.models.generateContent({
                model,
                contents: { parts },
                config,
            });

            const candidate = response.candidates?.[0];
            // Fix: Iterate through all parts to find the image part, do not assume it is the first part.
            if (candidate?.content?.parts) {
                for (const part of candidate.content.parts) {
                    if (part.inlineData) {
                        const base64ImageBytes = part.inlineData.data;
                        return `data:${part.inlineData.mimeType};base64,${base64ImageBytes}`;
                    }
                }
            }

            if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
                 throw new Error(`Image generation stopped unexpectedly. Reason: ${candidate.finishReason}. Please check your prompt for safety violations.`);
            }
            throw new Error("No image data received from API. The prompt might be too complex or the response was empty.");
        }

    } catch (error: any) {
        console.error("Gemini API call failed:", error);
        // Handle mandatory API key selection if the request fails due to permissions
        if (error?.message?.includes("Requested entity was not found.")) {
             if (model === 'gemini-3-pro-image-preview' || model.includes('veo')) {
                 await (window as any).aistudio.openSelectKey();
                 throw new Error("API selection error. A key selection dialog has been opened. Please select a valid paid project key and try again.");
             }
        }
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("An unexpected error occurred while calling the Gemini API.");
    }
};

export const expandImage = async (imageDataUrl: string, newAspectRatio: string, originalPrompt: string): Promise<string> => {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-2.5-flash-image';

    const [header, base64Data] = imageDataUrl.split(',');
    if (!header || !base64Data) {
        throw new Error("Invalid imageDataUrl format");
    }
    const mimeType = header.match(/:(.*?);/)?.[1] || 'image/png';

    const fullPrompt = `
**Objective:** You are an expert image editor AI. Your task is to expand the given image to a new aspect ratio of **${newAspectRatio}**.

**Core Directives (Strictly follow):**
1.  **Seamless Expansion:** Intelligently fill in the new, expanded areas of the canvas. The new content must seamlessly continue the existing scene, characters, lighting, and overall art style.
2.  **Preserve Original:** The content and quality of the original image area must be preserved perfectly. Do not alter or re-render the original pixels.
3.  **Contextual Awareness:** The original scene was about: "${originalPrompt}". Use this context to generate plausible and fitting extensions to the scene.
4.  **Aspect Ratio:** The final output image must strictly adhere to a ${newAspectRatio} aspect ratio.
`.trim();

    const parts = [
        { 
            inlineData: {
                data: base64Data,
                mimeType: mimeType,
            },
        },
        { text: fullPrompt },
    ];

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: {
                imageConfig: {
                    aspectRatio: newAspectRatio,
                },
            },
        });

        const candidate = response.candidates?.[0];
        // Fix: Iterate through all parts to find the image part.
        if (candidate?.content?.parts) {
            for (const part of candidate.content.parts) {
                if (part.inlineData) {
                    const base64ImageBytes = part.inlineData.data;
                    return `data:${part.inlineData.mimeType};base64,${base64ImageBytes}`;
                }
            }
        }

        if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
             throw new Error(`Image expansion stopped unexpectedly. Reason: ${candidate.finishReason}.`);
        }
        throw new Error("No image data received from API for expansion.");

    } catch (error) {
        console.error("Gemini API call failed during expansion:", error);
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("An unexpected error occurred while calling the Gemini API for expansion.");
    }
};

const getClosestAspectRatio = (width: number, height: number): string => {
    const ratio = width / height;
    const supported = ["16:9", "9:16", "1:1", "4:3", "3:4"];
    let bestMatch = "1:1";
    let minDiff = Number.MAX_VALUE;

    for (const s of supported) {
        const [sw, sh] = s.split(':').map(Number);
        const sRatio = sw / sh;
        const diff = Math.abs(ratio - sRatio);
        if (diff < minDiff) {
            minDiff = diff;
            bestMatch = s;
        }
    }
    return bestMatch;
};

export const addFrameToImage = async (imageDataUrl: string): Promise<string> => {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-2.5-flash-image';

    const [header, base64Data] = imageDataUrl.split(',');
    if (!header || !base64Data) {
        throw new Error("Invalid imageDataUrl format");
    }
    const mimeType = header.match(/:(.*?);/)?.[1] || 'image/png';

    const aspectRatio = await new Promise<string>((resolve) => {
        const img = new Image();
        img.onload = () => {
            resolve(getClosestAspectRatio(img.width, img.height));
        };
        img.onerror = () => {
            resolve('1:1'); 
        };
        img.src = imageDataUrl;
    });

    const fullPrompt = `
    **Task:** Edit the provided image.
    **Instruction:** Draw a thin red border frame around the very outer edge of the image.
    **Style:** The line should be thin, red, and clearly visible, hugging the canvas boundaries.
    **Constraint:** Preserve the inner image content perfectly. Do not crop or distort.
    **Translation:** เขียนกรอบรูปรอบภาพเป็นเส้นสีแดงบางๆ แค่พอมองเห็น ให้ชิดขอบที่สุด
    `.trim();

    const parts = [
        { 
            inlineData: {
                data: base64Data,
                mimeType: mimeType,
            },
        },
        { text: fullPrompt },
    ];

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: {
                imageConfig: {
                    aspectRatio: aspectRatio,
                },
            },
        });

        const candidate = response.candidates?.[0];
        // Fix: Iterate through all parts to find the image part.
        if (candidate?.content?.parts) {
            for (const part of candidate.content.parts) {
                if (part.inlineData) {
                    const base64ImageBytes = part.inlineData.data;
                    return `data:${part.inlineData.mimeType};base64,${base64ImageBytes}`;
                }
            }
        }

        if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
             throw new Error(`Image processing stopped unexpectedly. Reason: ${candidate.finishReason}.`);
        }
        throw new Error("No image data received from API.");

    } catch (error) {
        console.error("Gemini API call failed during frame addition:", error);
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("An unexpected error occurred while calling the Gemini API.");
    }
};

