import React, { useState, useEffect, useRef } from 'react';

export const ApiKeyManager: React.FC = () => {
  const [apiKey, setApiKey] = useState<string>('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Initial check: localStorage -> Environment -> placeholder
    const storedKey = localStorage.getItem('gemini_api_key');
    const envKey = (window as any).process?.env?.API_KEY;

    if (storedKey && storedKey.trim() !== '') {
      setApiKey(storedKey);
      if ((window as any).process?.env) {
        (window as any).process.env.API_KEY = storedKey;
      }
    } else if (envKey && envKey !== 'undefined' && envKey !== 'PLACEHOLDER_API_KEY') {
      setApiKey(envKey);
    } else {
      setApiKey('no API key');
    }
  }, []);

  const handleSend = () => {
    const val = apiKey.trim();
    if (val && val !== 'no API key' && val !== '') {
      localStorage.setItem('gemini_api_key', val);
      if ((window as any).process?.env) {
        (window as any).process.env.API_KEY = val;
      }
      alert('API Key saved to localStorage and applied successfully.');
    } else {
      alert('Please enter a valid API key.');
    }
  };

  const handleCopy = () => {
    if (apiKey && apiKey !== 'no API key' && apiKey !== '') {
      navigator.clipboard.writeText(apiKey).then(() => {
        alert('API Key copied to clipboard.');
      }).catch(err => {
        console.error('Failed to copy: ', err);
      });
    }
  };

  const handleClear = () => {
    setApiKey('');
    localStorage.removeItem('gemini_api_key');
    if ((window as any).process?.env) {
      (window as any).process.env.API_KEY = '';
    }
    inputRef.current?.focus();
  };

  const handleFocus = () => {
    if (apiKey === 'no API key') {
      setApiKey('');
    }
  };

  const handleBlur = () => {
    if (apiKey.trim() === '') {
      setApiKey('no API key');
    }
  };

  return (
    <div className="w-full bg-[#0d1117] border-b border-gray-800 flex flex-col z-[100] sticky top-0 shadow-xl">
      <div className="flex items-center justify-between px-4 py-1.5 bg-black/40">
        <div className="flex items-center gap-2">
          <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest flex items-center gap-2">
            <span className={`w-1.5 h-1.5 rounded-full ${apiKey && apiKey !== 'no API key' ? 'bg-green-500 shadow-[0_0_8px_#22c55e]' : 'bg-red-500'} animate-pulse`}></span>
            API key :
          </label>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleSend} 
            className="text-[9px] font-bold bg-red-600 hover:bg-red-700 text-white px-4 py-1 rounded transition-all active:scale-95 shadow-lg shadow-red-900/20"
          >
            SEND
          </button>
          <button 
            onClick={handleCopy} 
            className="text-[9px] font-bold bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-1 rounded transition-all active:scale-95 border border-gray-700"
          >
            COPY
          </button>
          <button 
            onClick={handleClear} 
            className="text-[9px] font-bold bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-1 rounded transition-all active:scale-95 border border-gray-700"
          >
            CLEAR
          </button>
        </div>
      </div>
      <div className="px-4 py-1 bg-black/20">
        <input
          ref={inputRef}
          type="text"
          value={apiKey}
          onChange={(e) => setApiKey(e.target.value)}
          onFocus={handleFocus}
          onBlur={handleBlur}
          className="w-full bg-transparent text-[#00ff41] font-mono text-xs focus:outline-none placeholder-gray-700 pb-1 h-6 selection:bg-green-500/30 selection:text-green-200"
          spellCheck={false}
          placeholder="Enter your Gemini API Key here..."
        />
      </div>
    </div>
  );
};

