        setError("Please enter at least one prompt.");
        return;
    }

    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    try {
      // Mandatory check for high-quality models that require user-provided billing keys
      await ensureApiKey(model);
    } catch (e) {
      setError("API Key selection is required for this model.");
      setIsLoading(false);
      return;
    }

    const selectedCharacters = characters.filter(c => c.isSelected && c.file);
    const dateStr = getFormattedDate();

