import React, { useState, useEffect, useRef } from 'react';

export const ApiKeyManager: React.FC = () => {
  const [apiKey, setApiKey] = useState<string>('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // โหลดค่าเริ่มต้น: localStorage -> Global process.env -> placeholder
    const storedKey = localStorage.getItem('gemini_api_key');
    const envKey = (window as any).process?.env?.API_KEY;

    if (storedKey && storedKey.trim() !== '') {
      setApiKey(storedKey);
      if ((window as any).process?.env) {
        (window as any).process.env.API_KEY = storedKey;
      }
    } else if (envKey && envKey !== 'undefined' && envKey !== 'PLACEHOLDER_API_KEY' && envKey !== '') {
      setApiKey(envKey);
    } else {
      setApiKey('no API key');
    }
  }, []);

  const handleSend = () => {
    const val = apiKey.trim();
    if (val && val !== 'no API key' && val !== '') {
      localStorage.setItem('gemini_api_key', val);
      if ((window as any).process?.env) {
        (window as any).process.env.API_KEY = val;
      }
      alert('API Key ถูกบันทึกและพร้อมใช้งานแล้ว');
    } else {
      alert('กรุณากรอก API Key ที่ถูกต้อง');
    }
  };

  const handleCopy = () => {
    const val = apiKey === 'no API key' ? '' : apiKey;
    if (val) {
      navigator.clipboard.writeText(val).then(() => {
        alert('คัดลอก API Key ลง Clipboard แล้ว');
      }).catch(err => {
        console.error('Failed to copy: ', err);
      });
    }
  };

  const handleClear = () => {
    setApiKey('');
    localStorage.removeItem('gemini_api_key');
    if ((window as any).process?.env) {
      (window as any).process.env.API_KEY = '';
    }
    inputRef.current?.focus();
  };

  const handleFocus = () => {
    if (apiKey === 'no API key') {
      setApiKey('');
    }
  };

  const handleBlur = () => {
    if (apiKey.trim() === '') {
      setApiKey('no API key');
    }
  };

  return (
    <div className="w-full bg-[#0d1117] border-b border-gray-800 flex flex-col z-[100] sticky top-0 shadow-2xl font-sans">
      {/* ส่วนควบคุมแถวบน */}
      <div className="flex items-center justify-between px-4 py-1.5 bg-black/60">
        <div className="flex items-center gap-2">
          <span className={`w-2 h-2 rounded-full ${apiKey && apiKey !== 'no API key' ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]'} transition-all duration-500`}></span>
          <label className="text-[11px] font-bold text-gray-500 uppercase tracking-widest select-none">
            API key :
          </label>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleSend} 
            className="text-[10px] font-black bg-red-600 hover:bg-red-700 text-white px-4 py-1 rounded transition-all active:scale-95 shadow-lg uppercase"
          >
            SEND
          </button>
          <button 
            onClick={handleCopy} 
            className="text-[10px] font-black bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-1 rounded transition-all active:scale-95 border border-gray-700 uppercase"
          >
            COPY
          </button>
          <button 
            onClick={handleClear} 
            className="text-[10px] font-black bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-1 rounded transition-all active:scale-95 border border-gray-700 uppercase"
          >
            CLEAR
          </button>
        </div>
      </div>

      {/* ส่วนแสดงข้อความแถวล่าง (Notepad Style) */}
      <div className="px-0 bg-black/40 border-t border-gray-800/30">
        <input
          ref={inputRef}
          type="text"
          value={apiKey}
          onChange={(e) => setApiKey(e.target.value)}
          onFocus={handleFocus}
          onBlur={handleBlur}
          className="w-full bg-transparent text-[#00ff41] font-mono text-sm px-4 py-2 focus:outline-none placeholder-gray-800 h-10 transition-colors selection:bg-green-500/30 overflow-x-auto whitespace-nowrap"
          spellCheck={false}
          autoComplete="off"
          placeholder="วาง API Key ของคุณที่นี่..."
        />
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { ResultsDisplay } from './components/ResultsDisplay';
import { Character, GeneratedImage } from './types';
import { generateStoryImage, expandImage, addFrameToImage } from './services/geminiService';
import { getFormattedDate } from './utils/fileUtils';
import { ExpandModal } from './components/ExpandModal';
import { ApiKeyManager } from './components/ApiKeyManager';

// Extend window interface for aistudio methods
declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

function App() {
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [previewImageUrl, setPreviewImageUrl] = useState<string | null>(null);
  const [expandingImage, setExpandingImage] = useState<GeneratedImage | null>(null);
  const [isExpanding, setIsExpanding] = useState(false);

  // ตรวจสอบความปลอดภัยเบื้องต้นเมื่อใช้โมเดลสูงๆ
  const ensureApiKey = useCallback(async (model: string) => {
    if (model === 'gemini-3-pro-image-preview') {
      // ถ้าไม่มีการตั้งค่าผ่าน Input เราจะลองเช็ค AI Studio ด้วย
      const hasStoredKey = localStorage.getItem('gemini_api_key');
      if (!hasStoredKey) {
          if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
              if (!(await window.aistudio.hasSelectedApiKey())) {
                  await window.aistudio.openSelectKey();
              }
          }
      }
    }
  }, []);

  const handleGenerate = useCallback(async (settings: {
    characters: Character[];
    prompts: string[];
    aspectRatio: string;
    imageStyle: string;
    model: string;
  }) => {
    const { characters, prompts, aspectRatio, imageStyle, model } = settings;

    if (prompts.length === 0 || prompts[0].trim() === '') {
        setError("กรุณากรอก Prompt อย่างน้อย 1 รายการ");
        return;
    }

    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    try {
      await ensureApiKey(model);
    } catch (e) {
      console.warn("API Key check skipped or failed", e);
    }

    const selectedCharacters = characters.filter(c => c.isSelected && c.file);
    const dateStr = getFormattedDate();

    for (let i = 0; i < prompts.length; i++) {
      const prompt = prompts[i];
      if (!prompt.trim()) continue;

      try {
        const imageDataUrl = await generateStoryImage(prompt, selectedCharacters, aspectRatio, imageStyle, model);
        const filename = `${String(i + 1).padStart(3, '0')}_${dateStr}.png`;

        setGeneratedImages(prev => [
          ...prev,
          { id: self.crypto.randomUUID(), imageDataUrl, prompt, filename }
        ]);
      } catch (e) {
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : 'เกิดข้อผิดพลาดไม่ทราบสาเหตุ';
        setError(`ไม่สามารถสร้างภาพสำหรับ prompt "${prompt}": ${errorMessage}`);
        break; 
      }
    }

    setIsLoading(false);
  }, [ensureApiKey]);

  const handleExpandRequest = useCallback((image: GeneratedImage) => {
    setExpandingImage(image);
  }, []);

  const handleCloseExpandModal = useCallback(() => {
    if (!isExpanding) {
      setExpandingImage(null);
    }
  }, [isExpanding]);

  const handleConfirmExpand = useCallback(async (newAspectRatio: string) => {
    if (!expandingImage) return;

    setIsExpanding(true);
    setError(null);
    const originalImage = expandingImage;

    try {
      const newImageDataUrl = await expandImage(originalImage.imageDataUrl, newAspectRatio, originalImage.prompt);
      const dateStr = getFormattedDate();

      const newImage: GeneratedImage = {
        id: self.crypto.randomUUID(),
        imageDataUrl: newImageDataUrl,
        prompt: `Expanded to ${newAspectRatio} from: "${originalImage.prompt}"`,
        filename: `${originalImage.filename.split('.png')[0]}_expanded_${newAspectRatio.replace(':', 'x')}.png`
      };

      setGeneratedImages(prevImages => {
        const originalIndex = prevImages.findIndex(img => img.id === originalImage.id);
        if (originalIndex === -1) {
          return [...prevImages, newImage]; 
        }
        const newImages = [...prevImages];
        newImages.splice(originalIndex + 1, 0, newImage);
        return newImages;
      });
      setExpandingImage(null);
    } catch (e) {
      console.error(e);
      const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred during expansion.';
      setError(`Failed to expand image: ${errorMessage}`);
      setExpandingImage(null);
    } finally {
      setIsExpanding(false);
    }
  }, [expandingImage]);

  const handleAddFrameToImage = useCallback(async (image: GeneratedImage) => {
    setIsLoading(true);
    setError(null);

    try {
      const newImageDataUrl = await addFrameToImage(image.imageDataUrl);

      const newImage: GeneratedImage = {
        id: self.crypto.randomUUID(),
        imageDataUrl: newImageDataUrl,
        prompt: `With Red Frame: "${image.prompt}"`,
        filename: `${image.filename.split('.png')[0]}_framed.png`
      };

      setGeneratedImages(prevImages => {
        const originalIndex = prevImages.findIndex(img => img.id === image.id);
        if (originalIndex === -1) {
          return [...prevImages, newImage];
        }
        const newImages = [...prevImages];
        newImages.splice(originalIndex + 1, 0, newImage);
        return newImages;
      });

    } catch (e) {
      console.error(e);
      const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred while adding frame.';
      setError(`Failed to add frame: ${errorMessage}`);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handlePreview = useCallback((imageUrl: string) => {
    setPreviewImageUrl(imageUrl);
  }, []);

  const closePreview = () => {
    setPreviewImageUrl(null);
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-200 font-sans flex flex-col">
      <ApiKeyManager />

      <header className="py-4 px-8 bg-gray-800/50 backdrop-blur-sm border-b border-gray-700 sticky top-0 sm:top-[66px] z-10 transition-all">
        <h1 className="text-2xl font-bold text-center text-transparent bg-clip-text bg-gradient-to-r from-red-500 to-yellow-500">
          Consistent AI Character Story Creator
        </h1>
      </header>

      <main className="flex flex-col lg:flex-row gap-8 p-4 md:p-8 flex-grow">
        <div className="lg:w-1/3 xl:w-1/4 lg:sticky lg:top-40 self-start">
          <ControlPanel onGenerate={handleGenerate} isLoading={isLoading} />
        </div>

        <div className="flex-1">
          <ResultsDisplay 
            images={generatedImages} 
            isLoading={isLoading} 
            error={error} 
            onPreview={handlePreview}
            onExpand={handleExpandRequest}
            onAddFrame={handleAddFrameToImage}
          />
        </div>
      </main>

      {previewImageUrl && (
        <div 
          className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 backdrop-blur-sm"
          onClick={closePreview}
