import React, { useState, useEffect, useRef } from 'react';

export const ApiKeyManager: React.FC = () => {
  const [apiKey, setApiKey] = useState<string>('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Initial load: check localStorage -> global process.env -> show placeholder
    const storedKey = localStorage.getItem('gemini_api_key');
    const envKey = (window as any).process?.env?.API_KEY;

    if (storedKey && storedKey.trim() !== '') {
      setApiKey(storedKey);
      if ((window as any).process?.env) {
        (window as any).process.env.API_KEY = storedKey;
      }
    } else if (envKey && envKey !== 'undefined' && envKey !== 'PLACEHOLDER_API_KEY' && envKey !== '') {
      setApiKey(envKey);
    } else {
      setApiKey('no API key');
    }
  }, []);

  const handleSend = () => {
    const val = apiKey.trim();
    if (val && val !== 'no API key' && val !== '') {
      localStorage.setItem('gemini_api_key', val);
      if ((window as any).process?.env) {
        (window as any).process.env.API_KEY = val;
      }
      alert('API Key updated and saved to localStorage.');
    } else {
      alert('Please enter a valid API key.');
    }
  };

  const handleCopy = () => {
    const val = apiKey === 'no API key' ? '' : apiKey;
    if (val) {
      navigator.clipboard.writeText(val).then(() => {
        alert('API Key copied to clipboard.');
      }).catch(err => {
        console.error('Failed to copy: ', err);
      });
    }
  };

  const handleClear = () => {
    setApiKey('');
    localStorage.removeItem('gemini_api_key');
    if ((window as any).process?.env) {
      (window as any).process.env.API_KEY = '';
    }
    inputRef.current?.focus();
  };

  const handleFocus = () => {
    if (apiKey === 'no API key') {
      setApiKey('');
    }
  };

  const handleBlur = () => {
    if (apiKey.trim() === '') {
      setApiKey('no API key');
    }
  };

  return (
    <div className="w-full bg-[#0d1117] border-b border-gray-800 flex flex-col z-[100] sticky top-0 shadow-2xl font-sans">
      {/* Top Controls Row */}
      <div className="flex items-center justify-between px-4 py-1.5 bg-black/60">
        <div className="flex items-center gap-2">
          <span className={`w-2 h-2 rounded-full ${apiKey && apiKey !== 'no API key' ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]'} transition-all duration-500`}></span>
          <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest select-none">
            API key :
          </label>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleSend} 
            className="text-[10px] font-black bg-red-600 hover:bg-red-700 text-white px-4 py-1 rounded transition-all active:scale-95 shadow-lg uppercase"
          >
            SEND
          </button>
          <button 
            onClick={handleCopy} 
            className="text-[10px] font-black bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-1 rounded transition-all active:scale-95 border border-gray-700 uppercase"
          >
            COPY
          </button>
          <button 
            onClick={handleClear} 
            className="text-[10px] font-black bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-1 rounded transition-all active:scale-95 border border-gray-700 uppercase"
          >
            CLEAR
          </button>
        </div>
      </div>

      {/* Notepad Style Input Row */}
      <div className="px-0 bg-black/40 border-t border-gray-800/30">
        <input
          ref={inputRef}
          type="text"
          value={apiKey}
          onChange={(e) => setApiKey(e.target.value)}
          onFocus={handleFocus}
          onBlur={handleBlur}
          className="w-full bg-transparent text-[#00ff41] font-mono text-sm px-4 py-2 focus:outline-none placeholder-gray-800 h-10 transition-colors selection:bg-green-500/30 overflow-x-auto whitespace-nowrap"
          spellCheck={false}
          autoComplete="off"
          placeholder="Paste your Gemini API Key here..."
        />
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { ResultsDisplay } from './components/ResultsDisplay';
import { Character, GeneratedImage } from './types';
import { generateStoryImage, expandImage, addFrameToImage } from './services/geminiService';
import { getFormattedDate } from './utils/fileUtils';
import { ExpandModal } from './components/ExpandModal';
import { ApiKeyManager } from './components/ApiKeyManager';

function App() {
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [previewImageUrl, setPreviewImageUrl] = useState<string | null>(null);
  const [expandingImage, setExpandingImage] = useState<GeneratedImage | null>(null);
  const [isExpanding, setIsExpanding] = useState(false);

  // ตรวจสอบความปลอดภัยและการเลือก API Key ตามแนวทางของ Gemini API สำหรับโมเดลขั้นสูง
  const ensureApiKey = useCallback(async (model: string) => {
    // สำหรับ gemini-3-pro-image-preview ต้องให้ผู้ใช้เลือก API Key ของตนเอง
    if (model === 'gemini-3-pro-image-preview') {
      const aistudio = (window as any).aistudio;
      if (aistudio && typeof aistudio.hasSelectedApiKey === 'function') {
        if (!(await aistudio.hasSelectedApiKey())) {
          await aistudio.openSelectKey();
          // อ้างอิงตามแนวทาง: ให้ถือว่าการเลือกสำเร็จหลังเรียกใช้ openSelectKey() เพื่อลดปัญหา Race Condition
        }
      }
    }
  }, []);

  const handleGenerate = useCallback(async (settings: {
    characters: Character[];
    prompts: string[];
    aspectRatio: string;
    imageStyle: string;
    model: string;
  }) => {
    const { characters, prompts, aspectRatio, imageStyle, model } = settings;

    if (prompts.length === 0 || prompts[0].trim() === '') {
        setError("กรุณากรอก Prompt อย่างน้อย 1 รายการ");
        return;
    }

    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    try {
      await ensureApiKey(model);
    } catch (e) {
      console.warn("API Key selection skipped or failed", e);
    }

    const selectedCharacters = characters.filter(c => c.isSelected && c.file);
    const dateStr = getFormattedDate();

    for (let i = 0; i < prompts.length; i++) {
      const prompt = prompts[i];
      if (!prompt.trim()) continue;

      try {
        const imageDataUrl = await generateStoryImage(prompt, selectedCharacters, aspectRatio, imageStyle, model);
        const filename = `${String(i + 1).padStart(3, '0')}_${dateStr}.png`;

        setGeneratedImages(prev => [
          ...prev,
          { id: self.crypto.randomUUID(), imageDataUrl, prompt, filename }
        ]);
      } catch (e) {
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : 'เกิดข้อผิดพลาดไม่ทราบสาเหตุ';

        // จัดการกรณี Requested entity was not found โดยให้ผู้ใช้เลือก Key ใหม่
        if (errorMessage.includes("Requested entity was not found")) {
            const aistudio = (window as any).aistudio;
            if (aistudio && typeof aistudio.openSelectKey === 'function') {
                await aistudio.openSelectKey();
            }
        }

        setError(`ไม่สามารถสร้างภาพสำหรับ prompt "${prompt}": ${errorMessage}`);
        break; 
      }
    }

    setIsLoading(false);
  }, [ensureApiKey]);

  const handleExpandRequest = useCallback((image: GeneratedImage) => {
    setExpandingImage(image);
  }, []);

  const handleCloseExpandModal = useCallback(() => {
    if (!isExpanding) {
      setExpandingImage(null);
    }
  }, [isExpanding]);

  const handleConfirmExpand = useCallback(async (newAspectRatio: string) => {
    if (!expandingImage) return;

    setIsExpanding(true);
    setError(null);
    const originalImage = expandingImage;

    try {
      const newImageDataUrl = await expandImage(originalImage.imageDataUrl, newAspectRatio, originalImage.prompt);
      const dateStr = getFormattedDate();

      const newImage: GeneratedImage = {
        id: self.crypto.randomUUID(),
        imageDataUrl: newImageDataUrl,
        prompt: `Expanded to ${newAspectRatio} from: "${originalImage.prompt}"`,
        filename: `${originalImage.filename.split('.png')[0]}_expanded_${newAspectRatio.replace(':', 'x')}.png`
      };

      setGeneratedImages(prevImages => {
        const originalIndex = prevImages.findIndex(img => img.id === originalImage.id);
        if (originalIndex === -1) {
          return [...prevImages, newImage]; 
        }
        const newImages = [...prevImages];
        newImages.splice(originalIndex + 1, 0, newImage);
        return newImages;
      });
      setExpandingImage(null);
    } catch (e) {
      console.error(e);
      const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred during expansion.';
      setError(`Failed to expand image: ${errorMessage}`);
      setExpandingImage(null);
    } finally {
      setIsExpanding(false);
    }
  }, [expandingImage]);

  const handleAddFrameToImage = useCallback(async (image: GeneratedImage) => {
    setIsLoading(true);
    setError(null);

    try {
      const newImageDataUrl = await addFrameToImage(image.imageDataUrl);

      const newImage: GeneratedImage = {
        id: self.crypto.randomUUID(),
        imageDataUrl: newImageDataUrl,
        prompt: `With Red Frame: "${image.prompt}"`,
        filename: `${image.filename.split('.png')[0]}_framed.png`
      };

      setGeneratedImages(prevImages => {
        const originalIndex = prevImages.findIndex(img => img.id === image.id);
        if (originalIndex === -1) {
          return [...prevImages, newImage];
        }
        const newImages = [...prevImages];
        newImages.splice(originalIndex + 1, 0, newImage);
        return newImages;
      });

    } catch (e) {
      console.error(e);
      const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred while adding frame.';
      setError(`Failed to add frame: ${errorMessage}`);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handlePreview = useCallback((imageUrl: string) => {
    setPreviewImageUrl(imageUrl);
  }, []);

  const closePreview = () => {
    setPreviewImageUrl(null);
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-200 font-sans flex flex-col">
      <ApiKeyManager />

      <header className="py-4 px-8 bg-gray-800/50 backdrop-blur-sm border-b border-gray-700 sticky top-[66px] z-10 transition-all">
        <h1 className="text-2xl font-bold text-center text-transparent bg-clip-text bg-gradient-to-r from-red-500 to-yellow-500">
          Consistent AI Character Story Creator
        </h1>
      </header>

      <main className="flex flex-col lg:flex-row gap-8 p-4 md:p-8 flex-grow">
        <div className="lg:w-1/3 xl:w-1/4 lg:sticky lg:top-[150px] self-start">
          <ControlPanel onGenerate={handleGenerate} isLoading={isLoading} />
        </div>

        <div className="flex-1">
          <ResultsDisplay 
            images={generatedImages} 
            isLoading={isLoading} 
            error={error} 
            onPreview={handlePreview}
            onExpand={handleExpandRequest}
            onAddFrame={handleAddFrameToImage}
          />
        </div>
      </main>

      {previewImageUrl && (
        <div 
          className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 backdrop-blur-sm"
          onClick={closePreview}
        >
          <div className="relative" onClick={(e) => e.stopPropagation()}>
            <img src={previewImageUrl} alt="Generated preview" className="max-w-[90vw] max-h-[90vh] object-contain rounded-lg shadow-2xl"/>
            <button 
              onClick={closePreview}
              className="absolute -top-4 -right-4 bg-white text-black rounded-full h-10 w-10 flex items-center justify-center text-2xl font-bold hover:bg-red-500 hover:text-white transition-transform transform hover:scale-110"
              aria-label="Close preview"
            >
              &times;
            </button>
          </div>
        </div>
      )}

      {expandingImage && (
        <ExpandModal
          image={expandingImage}
          onClose={handleCloseExpandModal}
          onExpand={handleConfirmExpand}
          isLoading={isExpanding}
        />
      )}
    </div>
  );
}

export default App;

import { GoogleGenAI } from "@google/genai";
import { Character } from '../types';

/**
 * ฟังก์ชันช่วยในการดึง API Key ล่าสุด
 */
const getApiKey = () => {
  return (window as any).process?.env?.API_KEY || "";
};

/**
 * ฟังก์ชันสำหรับประมวลผลข้อความ (Text Reasoning Tasks)
 */
export const processTextTask = async (
  text: string, 
  task: 'idea' | 'polish' | 'translate' | 'caption', 
  model: string
): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("ไม่พบ API Key กรุณากรอก API Key ที่ส่วนบนสุดของแอป");

  const ai = new GoogleGenAI({ apiKey });

  let systemInstruction = "";
  let prompt = "";

  switch(task) {
    case 'idea':
      systemInstruction = "คุณคือผู้ช่วยนักเขียนบทมืออาชีพ หน้าที่ของคุณคือการคิดไอเดียฉากใหม่ๆ";
      prompt = `ช่วยคิดไอเดียฉาก 3 ฉากที่น่าสนใจ โดยใช้บริบทเดิมคือ: "${text}" โดยแต่ละฉากให้แยกบรรทัดกัน และเน้นความต่อเนื่องของตัวละคร`;
      break;
    case 'polish':
      systemInstruction = "คุณคือผู้เชี่ยวชาญด้านการเขียน prompt สำหรับ AI Image Generator";
      prompt = `ช่วยขัดเกลาและขยายความ (Polish) คำสั่งต่อไปนี้ให้มีความละเอียด สวยงาม และได้ผลลัพธ์คุณภาพสูง: "${text}"`;
      break;
    case 'translate':
      systemInstruction = "คุณคือวิศวกรภาษา (Prompt Engineer) ที่เชี่ยวชาญการแปลคำสั่งเป็นภาษาอังกฤษสำหรับ AI สร้างภาพ";
      prompt = `แปลข้อความต่อไปนี้เป็นภาษาอังกฤษที่เหมาะสมที่สุดสำหรับ AI Image Generator: "${text}"`;
      break;
    case 'caption':
      systemInstruction = "คุณคือผู้เชี่ยวชาญด้านการเล่าเรื่องและเขียนแคปชั่นโซเชียลมีเดีย";
      prompt = `เขียนแคปชั่นสั้นๆ ที่น่าประทับใจสำหรับภาพที่มีคำบรรยายดังนี้: "${text}"`;
      break;
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { 
        systemInstruction,
        temperature: 0.8,
      }
    });
    return response.text || "";
  } catch (error) {
    console.error(`Text task (${task}) failed:`, error);
    throw error;
  }
};

export const generateStoryImage = async (
    prompt: string, 
    characters: Character[], 
    aspectRatio: string, 
    imageStyle: string,
    model: string = 'gemini-2.5-flash-image'
): Promise<string> => {

    const apiKey = getApiKey();
    const ai = new GoogleGenAI({ apiKey });

    const characterNames = characters.map(c => c.name).join(' and ');

    let styleDirective = '';
    if (imageStyle === 'Match Reference') {
      styleDirective = 'The overall artistic style (e.g., cartoon, anime, realistic) must perfectly match the reference images provided.';
    } else if (imageStyle === 'Black & White (Laser Printer)') {
      styleDirective = 'The artistic style must be a high-contrast, clean black and white line art, specifically optimized for printing on a monochrome laser printer. Use solid blacks and whites and avoid shades of gray. Maintain character identity but convert them into this line-art style.';
    } else {
      styleDirective = `The overall artistic style must be **${imageStyle}**. **CRITICAL INSTRUCTION:** You must translate the character's appearance from the reference images into this **${imageStyle}** style. Do not simply copy the art style of the reference images if it differs from ${imageStyle}. Keep the facial features and identity recognizable, but rendered in ${imageStyle}.`;
    }

    const fullPrompt = `
**Objective:** Create a high-resolution 4K image based on the description and references below.

**1. TARGET ARTISTIC STYLE (HIGHEST PRIORITY):**
${styleDirective}

**2. SCENE DESCRIPTION:**
${prompt}

**3. CHARACTERS:**
*   **Characters Involved:** ${characterNames}
*   **Identity & Consistency:** Use the provided reference images to strictly maintain the facial features, identity, hairstyle, and outfit of the characters.
*   **Style Adaptation:** **Apply the Target Artistic Style defined in Section 1 to these characters.** For example, if the style is 'Pixel Art', the characters must be rendered as Pixel Art, even if the reference image is a photograph.

**4. BACKGROUND:**
*   Ensure the background matches the scene description and the Target Artistic Style seamlessly.

**5. TECHNICAL:**
*   **Aspect Ratio:** ${aspectRatio}

**Final Check:** Ensure the result looks like a cohesive piece of art in the requested **${imageStyle}** style, featuring the specific characters described.
`.trim();

    try {
        if (model.includes('imagen')) {
            const imagenPrompt = `
            Scene: ${prompt}. 
            Characters: ${characterNames}.
            Style: ${imageStyle === 'Match Reference' ? 'High quality, detailed' : imageStyle}.
            Aspect Ratio: ${aspectRatio}.
            `.trim();

            const response = await ai.models.generateImages({
                model,
                prompt: imagenPrompt,
                config: {
                    numberOfImages: 1,
                    aspectRatio: aspectRatio as any,
                    outputMimeType: 'image/jpeg',
                },
            });

            if (response.generatedImages && response.generatedImages.length > 0) {
                 const base64ImageBytes = response.generatedImages[0].image.imageBytes;
                 return `data:image/jpeg;base64,${base64ImageBytes}`;
            } else {
                throw new Error("ไม่ได้รับข้อมูลรูปภาพจาก Imagen API");
            }

        } else {
            const parts: any[] = [{ text: fullPrompt }];

            for (const character of characters) {
                if (character.referenceFrames.length > 0) {
                    for (const frame of character.referenceFrames) {
                        parts.push({
                            inlineData: {
                                data: frame.data,
                                mimeType: frame.mimeType,
                            },
                        });
                    }
                }
            }

            const response = await ai.models.generateContent({
                model,
                contents: { parts },
                config: {
                    imageConfig: {
                        aspectRatio: aspectRatio as any,
                        ...(model === 'gemini-3-pro-image-preview' ? { imageSize: '1K' } : {})
                    },
                },
            });

            const candidate = response.candidates?.[0];
            const imagePart = candidate?.content?.parts?.find(p => p.inlineData);

            if (imagePart && imagePart.inlineData) {
                const base64ImageBytes = imagePart.inlineData.data;
                return `data:${imagePart.inlineData.mimeType};base64,${base64ImageBytes}`;
            } else {
                if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
                     throw new Error(`การสร้างภาพหยุดลงด้วยสาเหตุ: ${candidate.finishReason}`);
                }
                throw new Error("ไม่พบข้อมูลรูปภาพในการตอบกลับจาก API");
            }
        }

    } catch (error) {
        console.error("Gemini API call failed:", error);
        if (error instanceof Error) {
            throw new Error(`Gemini API Error: ${error.message}`);
        }
        throw new Error("เกิดข้อผิดพลาดในการเรียกใช้ Gemini API");
    }
};

export const expandImage = async (imageDataUrl: string, newAspectRatio: string, originalPrompt: string): Promise<string> => {
    const apiKey = getApiKey();
    const ai = new GoogleGenAI({ apiKey });
    const model = 'gemini-2.5-flash-image';

    const [header, base64Data] = imageDataUrl.split(',');
    if (!header || !base64Data) {
        throw new Error("รูปแบบข้อมูลรูปภาพไม่ถูกต้อง");
    }
    const mimeType = header.match(/:(.*?);/)?.[1] || 'image/png';

    const fullPrompt = `
**Objective:** You are an expert image editor AI. Your task is to expand the given image to a new aspect ratio of **${newAspectRatio}**.
1. Seamless Expansion: Fill new areas while continuing existing style.
2. Preserve Original: Do not alter original pixels.
3. Aspect Ratio: Strict ${newAspectRatio}.
`.trim();

    const parts = [
        { inlineData: { data: base64Data, mimeType: mimeType } },
        { text: fullPrompt },
    ];

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: { imageConfig: { aspectRatio: newAspectRatio as any } },
        });

        const candidate = response.candidates?.[0];
        const imagePart = candidate?.content?.parts?.find(p => p.inlineData);

        if (imagePart && imagePart.inlineData) {
            return `data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`;
        }
        throw new Error("ไม่พบข้อมูลรูปภาพจากการขยายภาพ");
    } catch (error) {
        throw error;
    }
};

const getClosestAspectRatio = (width: number, height: number): string => {
    const ratio = width / height;
    const supported = ["16:9", "9:16", "1:1", "4:3", "3:4"];
    let bestMatch = "1:1";
    let minDiff = Number.MAX_VALUE;
    for (const s of supported) {
        const [sw, sh] = s.split(':').map(Number);
        const sRatio = sw / sh;
        const diff = Math.abs(ratio - sRatio);
        if (diff < minDiff) { minDiff = diff; bestMatch = s; }
    }
    return bestMatch;
};

export const addFrameToImage = async (imageDataUrl: string): Promise<string> => {
    const apiKey = getApiKey();
    const ai = new GoogleGenAI({ apiKey });
    const model = 'gemini-2.5-flash-image';
    const [header, base64Data] = imageDataUrl.split(',');
    const mimeType = header.match(/:(.*?);/)?.[1] || 'image/png';

    const aspectRatio = await new Promise<string>((resolve) => {
        const img = new Image();
        img.onload = () => resolve(getClosestAspectRatio(img.width, img.height));
        img.onerror = () => resolve('1:1'); 
        img.src = imageDataUrl;
    });

    const fullPrompt = "Draw a thin red border frame around the very outer edge of the image. Preserve inner content perfectly.";
    const parts = [
        { inlineData: { data: base64Data, mimeType: mimeType } },
        { text: fullPrompt },
    ];

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: { imageConfig: { aspectRatio: aspectRatio as any } },
        });
        const candidate = response.candidates?.[0];
        const imagePart = candidate?.content?.parts?.find(p => p.inlineData);
        if (imagePart && imagePart.inlineData) {
            return `data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`;
        }
        throw new Error("ไม่พบข้อมูลรูปภาพหลังจากตีกรอบ");
    } catch (error) {
        throw error;
    }
};

