        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label htmlFor="text-model-select" className="block text-sm font-semibold mb-2">Text Reasoning Model</label>
          <select
            id="text-model-select"
            value={textModel}
            onChange={(e) => setTextModel(e.target.value)}
            className="w-full p-2 text-xs bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="gemini-3-flash-preview">Gemini 3 Flash (Recommended)</option>
            <option value="gemini-3-pro-preview">Gemini 3 Pro (Complex Reasoning)</option>
            <option value="gemini-flash-latest">Gemini Flash Latest</option>
            <option value="gemini-flash-lite-latest">Gemini Flash Lite</option>
          </select>
        </div>

        <div>
          <label htmlFor="model-select" className="block text-sm font-semibold mb-2">Image Model</label>
          <select
            id="model-select"
            value={selectedModel}
            onChange={(e) => setSelectedModel(e.target.value)}
            className="w-full p-2 text-xs bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
          >
            <option value="gemini-2.5-flash-image">Gemini 2.5 Flash Image</option>
            <option value="gemini-3-pro-image-preview">Gemini 3 Pro Image</option>
            <option value="gemini-flash-latest">Gemini Flash Latest</option>
            <option value="gemini-flash-lite-latest">Gemini Flash Lite</option>
            <option value="imagen-3.0-generate-001">Imagen 3.0</option>
            <option value="imagen-4.0-generate-001">Imagen 4.0 Latest</option>
          </select>
        </div>
      </div>

      <div>
        <label htmlFor="image-style" className="block text-lg font-semibold mb-2">Image Style</label>
        <select
          id="image-style"
          value={imageStyle}
          onChange={(e) => setImageStyle(e.target.value)}
          className="w-full p-2 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
        >
          <option value="Match Reference">Match Reference Style</option>
          <option value="Cartoon">Cartoon</option>
          <option value="Disney Cartoon">Disney Cartoon</option>
          <option value="ลายไทย">ลายไทย</option>
          <option value="Anime / Manga">Anime / Manga</option>
          <option value="Realistic">Realistic</option>
          <option value="Fantasy Art">Fantasy Art</option>
          <option value="Pixel Art">Pixel Art</option>
          <option value="Watercolor">Watercolor</option>
          <option value="Black & White (Laser Printer)">Black &amp; White (Laser Printer)</option>
        </select>
      </div>

      <div>
        <label htmlFor="aspect-ratio" className="block text-lg font-semibold mb-2">Aspect Ratio</label>
        <select
          id="aspect-ratio"
          value={aspectRatio}
          onChange={(e) => setAspectRatio(e.target.value)}
          className="w-full p-2 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
        >
          <option>16:9</option>
          <option>9:16</option>
          <option>1:1</option>
          <option>4:3</option>
          <option>Custom</option>
        </select>
        {aspectRatio === 'Custom' && (
          <input
            type="text"
            placeholder="e.g., 21:9"
            value={customAspectRatio}
            onChange={(e) => setCustomAspectRatio(e.target.value)}
            className="w-full mt-2 p-2 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
          />
        )}
      </div>

      <div>
        <div className="flex justify-between items-center mb-2">
          <label htmlFor="prompts" className="block text-lg font-semibold">Prompt List</label>
          <div className="flex items-center gap-1">
            <button onClick={handleOpenFileClick} disabled={isLoading} className="px-2 py-1 text-[10px] bg-gray-700 text-gray-300 rounded hover:bg-red-600 transition-colors">เปิด</button>
            <button onClick={handleCopyPrompts} disabled={!prompts || isLoading} className="px-2 py-1 text-[10px] bg-gray-700 text-gray-300 rounded hover:bg-red-600 transition-colors">{copyButtonText}</button>
            <button onClick={handleSavePrompts} disabled={!prompts || isLoading} className="px-2 py-1 text-[10px] bg-gray-700 text-gray-300 rounded hover:bg-red-600 transition-colors">บันทึก</button>
            <button onClick={handleClearPrompts} disabled={!prompts || isLoading} className="px-2 py-1 text-[10px] bg-gray-700 text-gray-300 rounded hover:bg-red-800 transition-colors">ล้าง</button>
          </div>
        </div>

        {/* ปุ่มเครื่องมือช่วยเขียน (Text Tasks) */}
        <div className="grid grid-cols-4 gap-1 mb-2">
            <button 
                onClick={() => handleTextTask('idea')} 
                disabled={isTextProcessing || isLoading} 
                className="py-1 text-[10px] bg-blue-600/20 hover:bg-blue-600 text-blue-300 hover:text-white rounded border border-blue-600/30 transition-all flex items-center justify-center gap-1"
            >
                {isTextProcessing ? <span className="animate-spin text-[8px]">●</span> : 'Idea'}
            </button>
            <button 
                onClick={() => handleTextTask('polish')} 
                disabled={isTextProcessing || isLoading} 
                className="py-1 text-[10px] bg-purple-600/20 hover:bg-purple-600 text-purple-300 hover:text-white rounded border border-purple-600/30 transition-all flex items-center justify-center gap-1"
            >
                {isTextProcessing ? <span className="animate-spin text-[8px]">●</span> : 'Polish'}
            </button>
            <button 
                onClick={() => handleTextTask('translate')} 
                disabled={isTextProcessing || isLoading} 
                className="py-1 text-[10px] bg-indigo-600/20 hover:bg-indigo-600 text-indigo-300 hover:text-white rounded border border-indigo-600/30 transition-all flex items-center justify-center gap-1"
            >
                {isTextProcessing ? <span className="animate-spin text-[8px]">●</span> : 'Translate'}
            </button>
            <button 
                onClick={() => handleTextTask('caption')} 
                disabled={isTextProcessing || isLoading} 
                className="py-1 text-[10px] bg-pink-600/20 hover:bg-pink-600 text-pink-300 hover:text-white rounded border border-pink-600/30 transition-all flex items-center justify-center gap-1"
            >
                {isTextProcessing ? <span className="animate-spin text-[8px]">●</span> : 'Caption'}
            </button>
        </div>

        <textarea
          id="prompts"
          ref={promptsTextareaRef}
          rows={10}
          value={prompts}
          onChange={(e) => setPrompts(e.target.value)}
          placeholder="ระบุฉากที่คุณต้องการที่นี่..."
          className="w-full p-3 bg-gray-700 border border-gray-600 rounded-md focus:outline-none focus:ring-2 focus:ring-red-500 placeholder-gray-500 text-sm"
        />

        <div className="flex gap-2 mt-3">
          <button onClick={handleThaiAdPrompt} disabled={isLoading} className="flex-1 bg-gray-700 hover:bg-gray-600 text-white font-medium py-2 px-1 rounded transition-colors border border-gray-600 text-[10px] sm:text-xs">ภาพโฆษณา</button>
          <button onClick={handleAdPrompt} disabled={isLoading} className="flex-1 bg-gray-700 hover:bg-gray-600 text-white font-medium py-2 px-1 rounded transition-colors border border-gray-600 text-[10px] sm:text-xs">Advertise</button>
          <button onClick={handleAddFramePrompt} disabled={isLoading} className="flex-1 bg-gray-700 hover:bg-gray-600 text-white font-medium py-2 px-1 rounded transition-colors border border-gray-600 text-[10px] sm:text-xs">Add Frame</button>
        </div>
      </div>

      <button
        onClick={handleGenerateClick}
        disabled={isLoading || isTextProcessing}
        className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 px-4 rounded-lg transition-all duration-300 ease-in-out disabled:bg-red-900 disabled:cursor-not-allowed flex items-center justify-center text-lg shadow-lg transform hover:scale-105 disabled:scale-100"
      >
        {isLoading ? 'Generating...' : 'Generate All Images'}
      </button>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import { Character } from '../types';

/**
 * ฟังก์ชันช่วยในการดึง API Key ล่าสุด
 */
const getApiKey = () => {
  return (window as any).process?.env?.API_KEY || "";
};

/**
 * ฟังก์ชันสำหรับประมวลผลข้อความ (Text Reasoning Tasks)
 */
export const processTextTask = async (
  text: string, 
  task: 'idea' | 'polish' | 'translate' | 'caption', 
  model: string
): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("ไม่พบ API Key กรุณากรอก API Key ที่ส่วนบนสุดของแอป");

  const ai = new GoogleGenAI({ apiKey });

  let systemInstruction = "";
  let prompt = "";

  switch(task) {
    case 'idea':
      systemInstruction = "คุณคือผู้ช่วยนักเขียนบทมืออาชีพ หน้าที่ของคุณคือการคิดไอเดียฉากใหม่ๆ";
      prompt = `ช่วยคิดไอเดียฉาก 3 ฉากที่น่าสนใจ โดยใช้บริบทเดิมคือ: "${text}" โดยแต่ละฉากให้แยกบรรทัดกัน และเน้นความต่อเนื่องของตัวละคร`;
      break;
    case 'polish':
      systemInstruction = "คุณคือผู้เชี่ยวชาญด้านการเขียน prompt สำหรับ AI Image Generator";
      prompt = `ช่วยขัดเกลาและขยายความ (Polish) คำสั่งต่อไปนี้ให้มีความละเอียด สวยงาม และได้ผลลัพธ์คุณภาพสูง: "${text}"`;
      break;
    case 'translate':
      systemInstruction = "คุณคือวิศวกรภาษา (Prompt Engineer) ที่เชี่ยวชาญการแปลคำสั่งเป็นภาษาอังกฤษสำหรับ AI สร้างภาพ";
      prompt = `แปลข้อความต่อไปนี้เป็นภาษาอังกฤษที่เหมาะสมที่สุดสำหรับ AI Image Generator: "${text}"`;
      break;
    case 'caption':
      systemInstruction = "คุณคือผู้เชี่ยวชาญด้านการเล่าเรื่องและเขียนแคปชั่นโซเชีลลมีเดีย";
      prompt = `เขียนแคปชั่นสั้นๆ ที่น่าประทับใจสำหรับภาพที่มีคำบรรยายดังนี้: "${text}"`;
      break;
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { 
        systemInstruction,
        temperature: 0.8,
      }
    });
    return response.text || "";
  } catch (error) {
    console.error(`Text task (${task}) failed:`, error);
    throw error;
  }
};

export const generateStoryImage = async (
    prompt: string, 
    characters: Character[], 
    aspectRatio: string, 
    imageStyle: string,
    model: string = 'gemini-2.5-flash-image'
): Promise<string> => {

    const apiKey = getApiKey();
    const ai = new GoogleGenAI({ apiKey });

    // ตรวจสอบว่าโมเดลเป็นตระกูลที่รองรับการสร้างภาพหรือไม่
    const isNanoBanana = model.includes('gemini-2.5') || model.includes('gemini-3') || model.includes('flash') || model.includes('lite');
    const isImagen = model.includes('imagen');

    const characterNames = characters.map(c => c.name).join(' and ');

    let styleDirective = '';
    if (imageStyle === 'Match Reference') {
      styleDirective = 'The overall artistic style (e.g., cartoon, anime, realistic) must perfectly match the reference images provided.';
    } else if (imageStyle === 'Black & White (Laser Printer)') {
      styleDirective = 'The artistic style must be a high-contrast, clean black and white line art, specifically optimized for printing on a monochrome laser printer. Use solid blacks and whites and avoid shades of gray. Maintain character identity but convert them into this line-art style.';
    } else {
      styleDirective = `The overall artistic style must be **${imageStyle}**. **CRITICAL INSTRUCTION:** You must translate the character's appearance from the reference images into this **${imageStyle}** style. Do not simply copy the art style of the reference images if it differs from ${imageStyle}. Keep the facial features and identity recognizable, but rendered in ${imageStyle}.`;
    }

    const fullPrompt = `
**Objective:** Create a high-resolution 4K image based on the description and references below.

**1. TARGET ARTISTIC STYLE (HIGHEST PRIORITY):**
${styleDirective}

**2. SCENE DESCRIPTION:**
${prompt}

**3. CHARACTERS:**
*   **Characters Involved:** ${characterNames}
*   **Identity & Consistency:** Use the provided reference images to strictly maintain the facial features, identity, hairstyle, and outfit of the characters.
*   **Style Adaptation:** **Apply the Target Artistic Style defined in Section 1 to these characters.** For example, if the style is 'Pixel Art', the characters must be rendered as Pixel Art, even if the reference image is a photograph.

**4. BACKGROUND:**
*   Ensure the background matches the scene description and the Target Artistic Style seamlessly.

**5. TECHNICAL:**
*   **Aspect Ratio:** ${aspectRatio}

**Final Check:** Ensure the result looks like a cohesive piece of art in the requested **${imageStyle}** style, featuring the specific characters described.
`.trim();

    try {
        if (isImagen) {
            const imagenPrompt = `
            Scene: ${prompt}. 
            Characters: ${characterNames}.
            Style: ${imageStyle === 'Match Reference' ? 'High quality, detailed' : imageStyle}.
            Aspect Ratio: ${aspectRatio}.
            `.trim();

            const config: any = {
                numberOfImages: 1,
                outputMimeType: 'image/jpeg',
            };

            // ใส่ Aspect Ratio เฉพาะเมื่อมีค่าและไม่เป็น Custom (หรือถ้าโมเดลรองรับ)
            if (aspectRatio && aspectRatio !== 'Custom') {
                config.aspectRatio = aspectRatio as any;
            }

            const response = await ai.models.generateImages({
                model,
                prompt: imagenPrompt,
                config,
            });

            if (response.generatedImages && response.generatedImages.length > 0) {
                 const base64ImageBytes = response.generatedImages[0].image.imageBytes;
                 return `data:image/jpeg;base64,${base64ImageBytes}`;
            } else {
                throw new Error("ไม่ได้รับข้อมูลรูปภาพจาก Imagen API");
            }

        } else {
            const parts: any[] = [{ text: fullPrompt }];

            for (const character of characters) {
                if (character.referenceFrames.length > 0) {
                    for (const frame of character.referenceFrames) {
                        parts.push({
                            inlineData: {
                                data: frame.data,
                                mimeType: frame.mimeType,
                            },
                        });
                    }
                }
            }

            const config: any = {};

            // เฉพาะโมเดลตระกูล Nano Banana (Gemini 2.5/3 Image) เท่านั้นที่ใช้ imageConfig
            // หากโมเดลอื่นถูกเลือกและไม่รองรับ ให้ข้าม imageConfig ไป
            if (isNanoBanana) {
                config.imageConfig = {
                    ...(aspectRatio && aspectRatio !== 'Custom' ? { aspectRatio: aspectRatio as any } : {}),
